(function(w){w.__PC_DUOC_CHUNKS=w.__PC_DUOC_CHUNKS||{};w.__PC_DUOC_CHUNKS["jci-01"]=[{"c":"ACC.01.00","ch":"ACC","t":"Bệnh nhân nhập viện hoặc tìm kiếm dịch vụ ngoại trú được sàng lọc để xác định xem nhu cầu chăm sóc sức khỏe của họ có phù hợp với sứ mệnh, phạm vi chăm sóc và nguồn lực của bệnh viện hay không.","p":"Việc kết hợp nhu cầu của bệnh nhân với sứ mệnh, phạm vi chăm sóc và các nguồn lực sẵn có của bệnh viện phụ\nthuộc vào việc thu thập thông tin về nhu cầu và tình trạng của bệnh nhân thông qua sàng lọc. Quyết định điều trị,\nchuyển viện hoặc giới thiệu chỉ được đưa ra sau khi có kết quả đánh giá sàng lọc.\n\nViệc sàng lọc nhu cầu và tình trạng của bệnh nhân có thể được thực hiện thông qua nhiều phương tiện khác nhau,\nbao gồm các phương tiện sau:\n• Tiêu chuẩn phân loại tại khoa cấp cứu hoặc phòng khám chăm sóc khẩn cấp/ngay lập tức ngoại trú\n• Đánh giá trực quan\n\n• Khám sức khỏe\n• Đánh giá vật lý, tâm lý, xét nghiệm lâm sàng hoặc chẩn đoán hình ảnh trước đó\n\nViệc sàng lọc có thể diễn ra tại nhiều điểm tiếp xúc khác nhau, bao gồm:\n• Tại nguồn giới thiệu (ví dụ, khám sức khỏe ban đầu)\n• Trong quá trình vận chuyển khẩn cấp\n• Khi đến bệnh viện\n\nNếu bệnh nhân đủ điều kiện nhập viện, nhu cầu chăm sóc của họ sẽ được xác định và ưu tiên. Những nhu cầu\nnày có thể bao gồm những điều sau đây:\n• Dịch vụ phòng ngừa\n• Dịch vụ chẩn đoán\n• Dịch vụ chữa bệnh hoặc điều trị\n• Dịch vụ phục hồi chức năng\n• Dịch vụ chăm sóc giảm nhẹ\n\nBệnh nhân được đưa vào dịch vụ hoặc đơn vị đáp ứng nhu cầu cấp thiết nhất của bệnh nhân.\n\nKhi bệnh viện không có khả năng lâm sàng để cung cấp các dịch vụ cần thiết, bệnh nhân được chuyển, giới thiệu hoặc hỗ\ntrợ xác định các nguồn dịch vụ để đáp ứng nhu cầu của họ. Bệnh viện chuyển viện phải cung cấp và ghi lại quá trình điều\ntrị ổn định trong khả năng của mình trước khi chuyển viện.","m":[{"t":"Kết quả sàng lọc quyết định bệnh nhân có được chấp nhận hay nhập viện hay không, tùy thuộc vào nhu cầu của bệnh nhân phù hợp với sứ mệnh, phạm vi chăm sóc và nguồn lực sẵn có của bệnh viện.","b":[]},{"t":"Bệnh nhân nằm ngoài nhiệm vụ, phạm vi chăm sóc hoặc nguồn lực sẵn có của bệnh viện được đánh giá và ổn định trong khả năng của bệnh viện trước khi chuyển viện.","b":[]},{"t":"Bệnh viện chuyển, giới thiệu hoặc hỗ trợ bệnh nhân hoặc gia đình xác định và/hoặc có được các nguồn chăm sóc phù hợp nếu nhu cầu của họ không phù hợp với sứ mệnh, phạm vi chăm sóc hoặc các nguồn lực sẵn có của bệnh viện.","b":[]},{"t":"Bệnh nhân được đưa vào dịch vụ hoặc đơn vị đáp ứng nhu cầu cấp thiết nhất của họ.","b":[]},{"t":"Các đánh giá và phương pháp điều trị được hoàn thành trước khi chuyển viện được ghi lại trong hồ sơ do bệnh viện chuyển viện lưu giữ. (Xem thêm ACC.03.00, ME 4)","b":[]},{"t":"Có một quy trình cung cấp kết quả xét nghiệm chẩn đoán cho những người chịu trách nhiệm xác định xem bệnh nhân có được nhập viện, chuyển viện hay chuyển tuyến hay không.","b":[]}],"sec":"Công nhận đối với bệnh viện"},{"c":"ACC.01.01","ch":"ACC","t":"Bệnh nhân có nhu cầu cấp cứu, khẩn cấp hoặc ngay lập tức được ưu tiên đánh giá và điều trị.","p":"Bệnh viện xác định bệnh nhân nào cần chăm sóc khẩn cấp, cấp cứu hoặc ngay lập tức và ưu tiên chăm sóc.\n\nBệnh nhân có nhu cầu chăm sóc khẩn cấp, cấp cứu và ngay lập tức được xác định và ưu tiên thông qua việc sử dụng quy\ntrình phân loại được công nhận, chẳng hạn như Chỉ số mức độ nghiêm trọng của trường hợp khẩn cấp hoặc Thang phân\nloại và mức độ nghiêm trọng của Canada. Nhân viên chịu trách nhiệm xác định và ưu tiên nhu cầu của bệnh nhân được đào\ntạo về quy trình phân loại đã chọn.\n\nQuy trình phân loại bao gồm việc nhận biết sớm các dấu hiệu và triệu chứng của bệnh truyền nhiễm. Bệnh nhân được xác\nđịnh là mắc hoặc nghi ngờ mắc các bệnh truyền nhiễm tiềm ẩn sẽ được phân loại và/hoặc cách ly.\n\nQuy trình phân loại bao gồm việc xác định những bệnh nhân cần theo dõi lâm sàng. Thời gian theo dõi lâm sàng cho phép\ncác bác sĩ lâm sàng phù hợp xác định xem bệnh nhân có cần nhập viện hay có thể xuất viện an toàn hay không. Có một quy\ntrình xác định để theo dõi lâm sàng trước khi nhập viện hoặc xuất viện.\n\nMột số xét nghiệm sàng lọc hoặc chẩn đoán có thể được yêu cầu đối với mọi bệnh nhân nhập viện hoặc\nbệnh viện có thể xác định các xét nghiệm và sàng lọc cụ thể cho từng nhóm bệnh nhân cụ thể dựa trên rủi\nro. Ví dụ bao gồm:\n• Sàng lọc bệnh nhân bị tiêu chảy hoạt động để tìm Clostridioides difficile (C. diff)\n• Sàng lọc bệnh nhân từ các tổ chức chăm sóc sức khỏe khác để tìm Staphylococcus aureus kháng methicillin\n\nQuy trình phân loại do tổ chức bệnh viện sử dụng đáp ứng các tiêu chí sau:\n• Dựa trên bằng chứng hoặc được thiết lập bởi một tổ chức chuyên nghiệp.\n• Phù hợp với nhóm bệnh nhân (ví dụ: công cụ phân loại nhi khoa so với người lớn, công cụ sản khoa).\n\nQuy trình quan sát lâm sàng bao gồm những nội dung sau:\n• Tiêu chí nhập viện hoặc xuất viện\n• Giới hạn thời gian trong thời gian quan sát\n• Xác định người quyết định bệnh nhân được nhập viện hay xuất viện\n\nCác xét nghiệm sàng lọc và chẩn đoán cần thiết để nhập viện dựa trên những nội dung sau:\n• Xu hướng hiện tại trong chăm sóc sức khỏe và bằng chứng khoa học hiện tại\n• Rủi ro cụ thể đối với nhóm bệnh nhân được tổ chức chăm sóc\n• Rủi ro cụ thể đối với môi trường và khu vực địa lý","m":[{"t":"Bệnh viện lựa chọn và sử dụng quy trình phân loại dựa trên bằng chứng, phù hợp với nhóm bệnh nhân của mình, để xác định và ưu tiên những bệnh nhân có nhu cầu cấp cứu, khẩn cấp và ngay lập tức.","b":[]},{"t":"Bệnh viện đã xác định những sàng lọc hoặc xét nghiệm chẩn đoán cụ thể nào phải được hoàn thành trước khi tiếp nhận hoặc đăng ký bệnh nhân.","b":[]},{"t":"Quá trình phân loại bao gồm việc phát hiện sớm các bệnh truyền nhiễm.","b":[]},{"t":"Nhân viên được đào tạo để sử dụng quy trình phân loại, bao gồm việc nhận biết sớm các bệnh truyền nhiễm.","b":[]},{"t":"Có một quy trình để giữ bệnh nhân lại để quan sát khi có chỉ định lâm sàng.","b":[]}],"sec":"Công nhận đối với bệnh viện"},{"c":"ACC.01.02","ch":"ACC","t":"Bệnh viện xem xét nhu cầu lâm sàng của bệnh nhân và thông báo cho bệnh nhân khi có sự chậm trễ bất thường đối với các dịch vụ chẩn đoán và/hoặc điều trị.","p":"Sự chậm trễ trong các dịch vụ chẩn đoán và điều trị có thể ảnh hưởng tiêu cực đến tình trạng của bệnh nhân,\nđặc biệt là khi tình trạng hoặc phương pháp điều trị của bệnh nhân bị giới hạn về thời gian. Bệnh nhân có\nquyền được biết và hiểu tác động tiềm ẩn của những sự chậm trễ này đối với sức khỏe của họ.\n\nBệnh nhân được thông báo khi có sự chậm trễ kéo dài đã biết đối với các dịch vụ chẩn đoán và/hoặc điều trị\nhoặc khi việc nhận được dịch vụ chăm sóc theo kế hoạch có thể yêu cầu phải đưa vào danh sách chờ. Ví dụ về\nnhững sự chậm trễ như vậy bao gồm:\n• Đang chờ ghép tạng\n• Sự chậm trễ trong việc nhận xét nghiệm chẩn đoán do số lượng cuộc hẹn hạn chế\n• Đang chờ phẫu thuật theo yêu cầu do số lượng phòng phẫu thuật hạn chế\nBệnh nhân được thông báo về những lý do liên quan đến sự chậm trễ và được thông báo về các phương án\nthay thế, nếu có. Yêu cầu này áp dụng cho dịch vụ chăm sóc nội trú và ngoại trú và/hoặc dịch vụ chẩn đoán.\nYêu cầu này\nkhông áp dụng cho thời gian chờ đợi nhỏ, thông thường hoặc dự kiến đối với dịch vụ chăm sóc ngoại trú hoặc\nchăm sóc nội trú. Ví dụ về những sự chậm trễ như vậy\nbao gồm:\n• Khi một nhà cung cấp bị chậm tiến độ trong một phòng khám\n• Khi phòng cấp cứu và phòng chờ của khoa cấp cứu đã đầy\n\n•\nKhi sự chậm trễ phù hợp với các tiêu chuẩn khu vực đối với các dịch vụ chuyên khoa, chẳng hạn như\nđiều trị ung thư hoặc ghép tạng\n\nĐây là những ví dụ hợp lý về sự chậm trễ, nhưng bệnh nhân và/hoặc gia đình của họ vẫn nên được thông báo về\nsự chậm trễ và lý do của chúng. Việc giao tiếp phù hợp và kịp thời là điều cần thiết để giải quyết sự lo lắng và thể\nhiện sự đồng cảm thực sự với bệnh nhân và/hoặc gia đình của họ.\n\nSự chậm trễ bất thường đòi hỏi phải ghi chép trong hồ sơ y tế của bệnh nhân. Việc ghi chép về sự chậm trễ bất\nthường bao gồm lý do của sự chậm trễ, để bệnh viện và nhà cung cấp dịch vụ chăm sóc sức khỏe hiểu được sự\nchậm trễ đó ảnh hưởng như thế nào đến việc chăm sóc bệnh nhân. Ví dụ về sự chậm trễ bất thường bao gồm\nnhững điều sau:\n• Không đủ nhân viên\n• Giao tiếp sai\n• Mẫu xét nghiệm bị từ chối","m":[{"t":"Bệnh nhân được thông báo khi có sự chậm trễ trong việc chăm sóc và/hoặc điều trị.","b":[]},{"t":"Bệnh nhân được thông báo về lý do chậm trễ và được cung cấp thông tin về các phương án thay thế có sẵn phù hợp với nhu cầu lâm sàng của họ.","b":[]},{"t":"Thông tin về sự chậm trễ bất thường và lý do chậm trễ được ghi lại trong hồ sơ y tế của bệnh nhân. Luồng bệnh nhân","b":[]}],"sec":"Công nhận đối với bệnh viện"},{"c":"ACC.02.00","ch":"ACC","t":"Bệnh viện có quy trình quản lý luồng bệnh nhân trong toàn bệnh viện bao gồm việc tiếp nhận và đăng ký bệnh nhân, tùy theo tình hình chăm sóc bệnh nhân.","p":"Quản lý luồng bệnh nhân trong toàn bệnh viện giúp cải thiện sự phối hợp chăm sóc, sự an toàn của bệnh nhân và kết quả\nsức khỏe. Điều cần thiết là giảm thiểu việc đưa bệnh nhân lên khoa cấp cứu hoặc các khu vực tạm thời khác trong bệnh\nviện.\n\nLuồng bệnh nhân là sự di chuyển của bệnh nhân trong toàn bệnh viện từ điểm tiếp nhận đến điểm xuất viện hoặc từ điểm\nđăng ký đến điểm xử lý. Quản lý hiệu quả các quy trình hỗ trợ luồng bệnh nhân có thể giảm thiểu sự chậm trễ trong việc\ncung cấp dịch vụ chăm sóc. Luồng bệnh nhân bao gồm những nội dung sau:\n• Tiếp nhận và xuất viện bệnh nhân\n• Tiếp nhận theo lịch trình, theo yêu cầu và cấp cứu\n• Đánh giá và điều trị bệnh nhân\n• Chuyển bệnh nhân giữa các đơn vị hoặc các cấp độ chăm sóc khác\n• Sự sẵn có của nhân viên và nguồn lực\n\nBệnh viện có quy trình quản lý luồng bệnh nhân. Các thành phần của quy trình bao gồm những điều sau:\n• Có giường bệnh nội trú tại các khu vực chăm sóc phù hợp\n• Có đội ngũ nhân viên được đào tạo và cấp chứng chỉ phù hợp\n• Tiến triển và di chuyển dự kiến của bệnh nhân qua tất cả các khu vực chăm sóc, bao gồm những điều sau:\no Khoa cấp cứu\no Đơn vị nội trú\no Phòng phẫu thuật và khu vực thủ thuật\no Khu vực xét nghiệm chẩn đoán\n• Có sẵn và hiệu quả các dịch vụ phi lâm sàng hỗ trợ chăm sóc bệnh nhân, bao gồm dịch vụ dọn dẹp\nvà vận chuyển\n\nBệnh viện phải chuẩn bị cho tình trạng quá tải bệnh nhân khi dòng bệnh nhân không tiến triển như mong đợi và\nkhi có một lượng bệnh nhân ồ ạt đổ về. Các kế hoạch chuẩn bị giải quyết các yêu cầu của bệnh nhân và nhân viên\nđể cung cấp dịch vụ chăm sóc an toàn cho bệnh nhân đang ở khoa cấp cứu hoặc được giữ tại các địa điểm tạm thời\nkhác.\n\nBệnh viện có một quy trình để quản lý tình trạng quá tải bệnh nhân đang ở khoa cấp cứu và các khu vực tạm thời\nkhác. Quy trình này bao gồm các nội dung sau:\n• Kế hoạch cơ sở để phân bổ không gian, tiện ích, thiết bị, dụng cụ y tế và vật tư\n• Kế hoạch biên chế\n• Khả năng tiếp cận và cung cấp nguồn lực lâm sàng, bao gồm các nội dung sau:\no Bệnh nhân quá tải hoặc đang ở nội trú được chăm sóc như bệnh nhân nhập viện.\no Bệnh nhân quá tải hoặc đang ở nội trú có quyền tiếp cận các dịch vụ lâm sàng như bệnh nhân nhập viện.\no Bệnh nhân quá tải hoặc đang ở nội trú có quyền tiếp cận các dịch vụ phi lâm sàng như bệnh nhân nhập viện.\n• Một mốc thời gian đã thiết lập để chuyển bệnh nhân từ khu vực tạm trú hoặc khoa cấp cứu đến các giường bệnh\nnội trú thích hợp\n\nNhân viên từ khắp bệnh viện có thể đóng góp vào việc hiểu và giải quyết các vấn đề trong dòng bệnh nhân. Bệnh\nviện thiết lập các biện pháp và mục tiêu để xem xét hiệu quả của quy trình luồng bệnh nhân. Các biện pháp và mục\ntiêu này được theo dõi và thông báo các chiến lược để cải thiện luồng bệnh nhân. Hiệu quả của các cải tiến quy trình\nđối với luồng bệnh nhân được đánh giá.","m":[{"t":"Bệnh viện thực hiện quy trình luồng bệnh nhân, bao gồm:","b":["Có giường bệnh phù hợp","Đội ngũ nhân viên được đào tạo bài bản","Dự kiến di chuyển và tiến triển trong toàn bộ khu vực chăm sóc","Có các dịch vụ phi lâm sàng"]},{"t":"Bệnh viện có quy trình tiếp nhận bệnh nhân, bất kể họ đến từ đâu, bao gồm quy trình đăng ký cho những bệnh nhân không cần tiếp nhận.","b":[]},{"t":"Bệnh viện lập kế hoạch và cung cấp dịch vụ chăm sóc cho những bệnh nhân được đưa vào khoa cấp cứu và các khu vực tạm trú khác, bao gồm:","b":["Phân bổ không gian, tiện ích, thiết bị, dụng cụ y tế và vật tư","Kế hoạch biên chế","Tính khả dụng của các nguồn lực lâm sàng","Tính khả dụng của các nguồn lực phi lâm sàng","Cung cấp dịch vụ chăm sóc kịp thời và tương đương để đáp ứng nhu cầu của bệnh nhân","Giới hạn thời gian đưa bệnh nhân vào khoa cấp cứu và các khu vực tạm trú khác và quy trình quản lý bệnh nhân khi thời gian đưa bệnh nhân vào khoa tạm trú vượt quá giới hạn thời gian này"]},{"t":"D Các quy trình lưu chuyển bệnh nhân được xem xét về hiệu quả và các cải tiến quy trình được xác định và triển khai.","b":[]}],"sec":"Dòng bệnh nhân"},{"c":"ACC.02.01","ch":"ACC","t":"Vào thời điểm nhập viện, bệnh nhân và gia đình sẽ được giáo dục và định hướng về khu vực chăm sóc bệnh nhân, thông tin về dịch vụ chăm sóc được đề xuất và mọi chi phí dự kiến cho dịch vụ chăm sóc, cũng như kết quả mong đợi của dịch vụ chăm sóc.","p":"Định hướng về môi trường chăm sóc, bao gồm các thiết bị liên quan đến việc chăm sóc và các dịch vụ được cung\ncấp, là một thành phần thiết yếu của sự an toàn của bệnh nhân. Bệnh nhân và gia đình họ nhận được đủ thông\ntin để đưa ra quyết định sáng suốt. Bệnh nhân và nhân viên lâm sàng hiểu phạm vi và giới hạn của sự đồng ý\nchung (nếu được bệnh viện sử dụng) để bảo vệ quyền tự chủ và quyền của bệnh nhân.\n\nBệnh nhân và gia đình họ nhận được thông tin về dịch vụ chăm sóc được đề xuất, kết quả mong đợi của dịch vụ chăm sóc\nvà bất kỳ chi phí dự kiến nào cho dịch vụ chăm sóc khi không được chi trả bởi nguồn công hoặc tư. Thông tin này có thể\nđược cung cấp dưới dạng tài liệu viết hoặc thông qua giải thích bằng lời nói. Thông tin này cũng phải được ghi chú trong\nhồ sơ y tế của bệnh nhân.\n\nBệnh viện tìm cách giảm thiểu mọi rào cản tài chính cho bệnh nhân. Các ví dụ bao gồm:\n• Cung cấp đơn xin hỗ trợ tài chính\n• Xác định các nguồn tài trợ từ thiện cho dịch vụ chăm sóc sức khỏe\n• Cung cấp đơn thuốc cho thuốc gốc thay vì thuốc có nhãn hiệu\n\nKhi được sử dụng, sự đồng ý chung bao gồm:\n• Phạm vi của sự đồng ý chung (ví dụ, những xét nghiệm và phương pháp điều trị nào được bao gồm trong sự đồng ý\nchung)\n• Những xét nghiệm và phương pháp điều trị nào yêu cầu sự đồng ý có thông tin bổ sung\n• Bệnh nhân nhận thông tin như thế nào (ví dụ, thông qua cổng thông tin bệnh nhân hoặc tin nhắn văn bản)\n\nBệnh viện chỉ định cách ghi lại sự đồng ý chung trong hồ sơ y tế của bệnh nhân.\n\nBệnh viện có thể dựa vào sự đồng ý ngụ ý hoặc xin sự đồng ý chung để điều trị khi bệnh nhân được nhập viện hoặc đăng\nký lần đầu tiên. Bệnh viện không bắt buộc phải sử dụng sự đồng ý chung trừ khi luật pháp và quy định yêu cầu. Bất kể có\nđược sự đồng ý chung hay không, tất cả bệnh nhân đều được thông báo về những xét nghiệm và phương pháp điều trị nào\ncần có sự đồng ý có thông tin bổ sung.\n\nTất cả bệnh nhân đều được thông báo về khả năng sinh viên tham gia vào quá trình chăm sóc của họ; ví dụ, sinh viên y\nkhoa, sinh viên điều dưỡng, sinh viên vật lý trị liệu, sinh viên trị liệu hô hấp.","m":[{"t":"Bệnh nhân và gia đình được giáo dục và định hướng về lĩnh vực chăm sóc bệnh nhân.","b":[]},{"t":"Bệnh nhân và gia đình nhận được thông tin về dịch vụ, phương pháp điều trị và chăm sóc được đề xuất, bao gồm kết quả mong đợi.","b":[]},{"t":"Bệnh nhân và gia đình nhận được thông tin về bất kỳ chi phí dự kiến nào liên quan đến dịch vụ, phương pháp điều trị và chăm sóc được đề xuất.","b":[]},{"t":"Bệnh nhân và gia đình được thông báo về phạm vi của bản đồng ý chung, nếu bệnh viện sử dụng. (Xem thêm","b":[]},{"t":"PCC.03.00, ME 3)","b":[]},{"t":"D Bệnh viện xác định, bằng văn bản, cách thức ghi lại bản đồng ý chung trong hồ sơ y tế của bệnh nhân, nếu bệnh viện sử dụng. (Xem thêm PCC.03.00, ME 1)","b":[]},{"t":"Tất cả bệnh nhân đều nhận được thông tin về khả năng sinh viên và học viên tham gia vào các quy trình chăm sóc.","b":[]}],"sec":"Dòng bệnh nhân"},{"c":"ACC.02.02","ch":"ACC","t":"Bệnh viện thiết lập các tiêu chí để nhập viện và xuất viện từ các đơn vị hoặc khoa cung cấp dịch vụ chuyên khoa.","p":"Các tiêu chí cụ thể để nhập viện và xuất viện từ các đơn vị hoặc khoa chăm sóc đặc biệt hoặc chuyên khoa đảm bảo rằng\nbệnh nhân đang nhận được mức độ hoặc loại chăm sóc phù hợp và khuyến khích sử dụng hiệu quả các nguồn lực hạn chế\nnày.\n\nCác đơn vị hoặc khoa cung cấp dịch vụ chăm sóc đặc biệt hoặc chuyên khoa tốn kém, sử dụng nhiều nguồn lực và thường\nbị hạn chế về không gian và nhân sự. Bệnh viện nên hạn chế việc nhập viện vào các đơn vị hoặc khoa này để đảm bảo việc\nsử dụng phù hợp các khu vực và nguồn lực này. Bệnh viện phải thiết lập các tiêu chí liên quan đến bệnh nhân cần mức độ\nvà loại chăm sóc do các đơn vị hoặc khoa chuyên khoa này cung cấp. Tiêu chí phải được thực hiện nhất quán trong toàn\nbệnh viện và giữa các nhân viên lâm sàng để xác định tình trạng bệnh nhân. Ví dụ về các đơn vị hoặc khoa này và\ntiêu chí tuyển sinh của họ bao gồm:\n\n•\nTiêu chuẩn để nhập viện vào khoa bỏng có thể bao gồm tỷ lệ phần trăm cụ thể của bề mặt cơ thể bị\nbỏng và/hoặc liệu vết bỏng có phải là bỏng cấp độ hai hay cấp độ ba hay không.\n•\nTiêu chuẩn để nhập viện vào khoa chăm sóc tích cực có thể yêu cầu bệnh nhân phải được đặt nội khí\nquản, cần theo dõi chặt chẽ các thay đổi quan trọng hoặc cần thêm thiết bị (ví dụ: đường truyền tĩnh\nmạch và máy bơm, ống nuôi ăn, ống dẫn lưu và ống thông).\n•\nViệc nhập viện vào khoa chăm sóc sau gây mê so với khoa chăm sóc tích cực phẫu thuật có thể được\nxác định bằng cách xem bệnh nhân có còn được đặt nội khí quản, đang dùng thuốc làm co mạch hay\ncần chăm sóc vết thương phức tạp hay không.\n\nTiêu chuẩn được sử dụng để xác định việc nhập viện trực tiếp vào khoa hoặc phòng ban (ví dụ: trực tiếp từ khoa\ncấp cứu). Tiêu chuẩn cũng được sử dụng để xác định việc nhập viện vào khoa hoặc phòng ban từ một khu vực lâm\nsàng khác trong bệnh viện hoặc được chuyển từ một bệnh viện khác.\n\nBệnh nhân được nhập viện vào khoa hoặc phòng ban chuyên khoa cần được đánh giá lại định kỳ để xác định thời\nđiểm bệnh nhân tiếp tục đáp ứng tiêu chuẩn cho các dịch vụ chuyên khoa. Ví dụ về bệnh nhân không còn đáp ứng\ntiêu chuẩn bao gồm:\n•\nBệnh nhân được nhập viện vào khoa chăm sóc tích cực có tình trạng sinh lý ổn định và không còn cần theo dõi\nliên tục nữa\n•\nBệnh nhân có tình trạng sinh lý xấu đi và mục tiêu chăm sóc được chuyển hướng sang chăm sóc giảm nhẹ hoặc\nan ủi, cần theo dõi ít chuyên sâu hơn\n\nBất cứ khi nào có thể, tiêu chuẩn cho các khoa và phòng chuyên khoa hoặc chuyên sâu phải đáp ứng các yêu cầu sau:\n•\nSử dụng tiêu chuẩn ưu tiên hoặc tiêu chuẩn mức độ nghiêm trọng của bệnh.\n•\nDựa trên các thông số chẩn đoán và/hoặc khách quan.\n•\nSử dụng tiêu chuẩn dựa trên sinh lý cho các dịch vụ y tế và phẫu thuật.\n•\nSử dụng tiêu chuẩn dựa trên tâm lý cho các dịch vụ tâm thần.\n•\nBao gồm công nghệ, biện pháp can thiệp và thuốc cần thiết để cứu sống hoặc duy trì sự sống. Ví dụ về công\nnghệ, biện pháp can thiệp và thuốc như vậy bao gồm:\no\nMáy thở hoặc các phương tiện hỗ trợ hô hấp khác\no\nThuốc làm co mạch hoặc các loại thuốc khác cần theo dõi thường xuyên hoặc liên tục\no\nTần suất quan sát trực tiếp bệnh nhân\no\nTần suất và mức độ phức tạp của việc chăm sóc vết thương\n\nCác đơn vị hoặc khoa chuyên sâu hoặc chuyên khoa thiết lập các tiêu chí để đánh giá lại bệnh nhân đã nhập viện,\nbao gồm:\n•\nKhi nào và tần suất bệnh nhân cần được đánh giá lại để tiếp tục chăm sóc hoặc chuyển sang một cấp độ chăm\nsóc khác\n•\nCác thông số chẩn đoán và/hoặc khách quan để chuyển an toàn sang một cấp độ chăm sóc khác\n•\nCác tiêu chí dựa trên sinh lý và/hoặc tâm lý\n•\nTần suất và loại công nghệ, biện pháp can thiệp và thuốc để giảm leo thang điều trị","m":[{"t":"Bệnh viện đã thiết lập các tiêu chí nhập viện bằng văn bản, dựa trên các thông số ưu tiên, chẩn đoán và/hoặc khách quan, cho các đơn vị hoặc khoa chuyên khoa.","b":[]},{"t":"Bệnh viện đã thiết lập các tiêu chí xuất viện và/hoặc chuyển viện bằng văn bản từ các đơn vị hoặc khoa chuyên khoa đến một cấp độ chăm sóc khác.","b":[]},{"t":"Hồ sơ bệnh án của những bệnh nhân được nhận vào các đơn vị hoặc khoa chuyên khoa có bằng chứng cho thấy họ đáp ứng các tiêu chí về chăm sóc, điều trị và dịch vụ. (Xem thêm GLD.06.00, ME 3)","b":[]},{"t":"Hồ sơ bệnh án của những bệnh nhân được chuyển hoặc xuất viện khỏi các đơn vị hoặc khoa chuyên khoa có bằng chứng cho thấy họ đáp ứng các tiêu chí xuất viện. (Xem thêm ACC.03.00, ME 1; ACC.05.00, ME 1; GLD.06.00, ME 4) Tiếp cận dịch vụ chăm sóc và tính liên tục của dịch vụ chăm sóc (ACC) Sự liên tục của việc chăm sóc","b":[]}],"sec":"Continuity of Care (ACC)"},{"c":"ACC.03.00","ch":"ACC","t":"Bệnh viện cung cấp dịch vụ chăm sóc bệnh nhân liên tục và phối hợp giữa các nhà cung cấp dịch vụ chăm sóc sức khỏe.","p":"Sự phối hợp và tính liên tục trong chăm sóc giữa các bác sĩ chăm sóc sức khỏe giúp cải thiện sự an toàn và kết quả\ncủa bệnh nhân. Sự phối hợp được thực hiện thông qua việc tiếp cận thông tin bệnh nhân, thông tin này rất cần\nthiết cho các quy trình này. Do đó, các bác sĩ chăm sóc sức khỏe tham gia vào quá trình chăm sóc, điều trị và dịch\nvụ của bệnh nhân được tiếp cận thông tin có liên quan.\n\nBệnh nhân được chuyển trong bệnh viện giữa các dịch vụ và đơn vị hoặc khoa khác nhau. Bệnh viện xác định các\ncá nhân để phối hợp chăm sóc và dịch vụ cho bệnh nhân. Nhiều bác sĩ chăm sóc sức khỏe chăm sóc bệnh nhân\ntrong toàn bệnh viện. Trong suốt tất cả các giai đoạn chăm sóc, nhu cầu của bệnh nhân được kết hợp với mức độ\nchăm sóc và nguồn lực cần thiết để chăm sóc. Khi cần thiết, bệnh nhân được chuyển hoặc giới thiệu đến các nguồn\nlực hoặc dịch vụ bên ngoài bệnh viện. Bệnh viện thiết lập các tiêu chí hoặc chính sách để xác định tính phù hợp\ncủa việc chuyển viện trong và ngoài bệnh viện.\n\nTính liên tục được tăng cường khi tất cả các bác sĩ chăm sóc sức khỏe đều có thông tin cần thiết từ kinh nghiệm y\ntế hiện tại và trước đây của bệnh nhân để đưa ra quyết định về việc chăm sóc bệnh nhân. Khi nhiều người ra quyết\nđịnh cùng cung cấp dịch vụ chăm sóc, những người ra quyết định này sẽ đồng ý về dịch vụ chăm sóc và dịch vụ sẽ\nđược cung cấp.\n\nBệnh viện triển khai các quy trình để đảm bảo tính liên tục và phối hợp chăm sóc giữa các bác sĩ, y tá và các chuyên\ngia chăm sóc sức khỏe khác trong mọi bối cảnh, bao gồm:\n• Dịch vụ cấp cứu và nhập viện nội trú\n• Dịch vụ chẩn đoán\n• Dịch vụ điều trị phẫu thuật và không phẫu thuật\n• Chương trình chăm sóc ngoại trú\n• Các tổ chức khác và các bối cảnh chăm sóc khác\n\nHồ sơ bệnh án của bệnh nhân là nguồn thông tin chính để chăm sóc bệnh nhân và là công cụ giao tiếp thiết yếu.\nHồ sơ bệnh án phải chứa thông tin hiện tại và phải có sẵn trong quá trình chăm sóc nội trú và khám ngoại trú. Ghi\nchú về y tế, điều dưỡng và các ghi chú chăm sóc bệnh nhân khác phải có sẵn cho tất cả các chuyên gia chăm sóc sức\nkhỏe của bệnh nhân khi họ cần chúng để chăm sóc bệnh nhân.\n\nHồ sơ chăm sóc sức khỏe đầy đủ của bệnh nhân được chuyển cùng với bệnh nhân khi thay đổi nhóm chăm sóc hoặc các cơ\nsở trong bệnh viện để các phương pháp điều trị, thuốc men và các can thiệp khác có thể tiếp tục mà không bị gián đoạn. Khi\nbệnh nhân được chuyển đến một tổ chức bên ngoài, bệnh viện cung cấp cho nhóm chăm sóc tiếp nhận bệnh nhân một bản\nsao hồ sơ y tế của bệnh nhân hoặc bản tóm tắt thông tin cần thiết từ hồ sơ chăm sóc sức khỏe của bệnh nhân.\n\nKhi chuyển bệnh nhân đến một tổ chức bên ngoài, bệnh viện có thể chuyển một bản sao hồ sơ y tế của bệnh nhân hoặc\ngửi bản tóm tắt chuyển cùng với bệnh nhân. Bản tóm tắt chuyển bao gồm các thông tin sau từ hồ sơ chăm sóc sức khỏe của\nbệnh nhân:\n• Khiếu nại chính\n• Phát hiện quan trọng\n• Chẩn đoán\n• Các thủ thuật đã thực hiện\n• Thuốc men\n• Các phương pháp điều trị khác\n• Tình trạng bệnh nhân tại thời điểm chuyển\n\nCác quy trình phối hợp và liên tục chăm sóc được hỗ trợ bởi những điều sau:\n• Hướng dẫn\n• Lộ trình lâm sàng\n• Biểu mẫu giới thiệu\n• Danh sách kiểm tra","m":[{"t":"Lãnh đạo bệnh viện triển khai các quy trình hỗ trợ tính liên tục và phối hợp chăm sóc trên tất cả các cơ sở chăm sóc. (Xem thêm ACC.02.02, ME 4; ACC.05.00, ME 1; GLD.06.00, ME 4)","b":[]},{"t":"Hồ sơ bệnh án của bệnh nhân được cung cấp cho những bác sĩ được phép truy cập và cần hồ sơ này để chăm sóc bệnh nhân. (Xem thêm MOI.01.01, ME 4)","b":[]},{"t":"Hồ sơ bệnh án của bệnh nhân được cập nhật thông tin mới nhất của bệnh nhân.","b":[]},{"t":"Hồ sơ bệnh án của bệnh nhân hoặc bản tóm tắt thông tin chăm sóc bệnh nhân được chuyển cùng bệnh nhân đến một dịch vụ hoặc đơn vị khác trong bệnh viện. (Xem thêm ACC.01.00, ME 5)","b":[]},{"t":"Tóm tắt chuyển giao bằng văn bản của hồ sơ y tế của bệnh nhân bao gồm, tối thiểu, những thông tin sau:","b":["Lý do nhập viện","Các phát hiện và kết quả xét nghiệm quan trọng","Chẩn đoán","Các thủ thuật đã thực hiện","Thuốc đã dùng trong thời gian nằm viện, bao gồm lần dùng thuốc cuối cùng và thuốc hiện tại (Xem thêm MMU.04.02, ME 2)","Các phương pháp điều trị khác","Tình trạng bệnh nhân tại thời điểm chuyển viện"]},{"t":"Sự phối hợp và tính liên tục của việc chăm sóc được hỗ trợ bằng nhiều công cụ khác nhau, chẳng hạn như kế hoạch chăm sóc, hướng dẫn hoặc giao thức.","b":[]}],"sec":"Sự liên tục của việc chăm sóc"},{"c":"ACC.03.01","ch":"ACC","t":"Có một cá nhân đủ trình độ chịu trách nhiệm chăm sóc bệnh nhân.","p":"Một cá nhân được xác định rõ ràng giám sát toàn bộ thời gian nằm viện của bệnh nhân sẽ cải thiện\ntính liên tục, sự phối hợp, sự hài lòng của bệnh nhân, chất lượng và kết quả chăm sóc lâm sàng.\n\nCá nhân chịu trách nhiệm về việc phối hợp chăm sóc tổng thể của bệnh nhân được xác định rõ\nràng, cho tất cả các giai đoạn chăm sóc bệnh nhân khác nhau. Cá nhân này có thể là bác sĩ hoặc một\ncá nhân đủ điều kiện khác. Cá nhân chịu trách nhiệm được xác định trong hồ sơ y tế của bệnh\nnhân. Cá nhân này hợp tác và trao đổi với các bác sĩ chăm sóc sức khỏe khác. Khi có nhiều hơn một\ncá nhân chịu trách nhiệm\nphối hợp chăm sóc, khả năng xảy ra sự không chắc chắn và thiếu sự phối hợp hiệu quả sẽ cao hơn.\nChính sách của bệnh viện xác định quy trình chuyển giao trách nhiệm cho một cá nhân khác trong\nkỳ nghỉ, ngày lễ và các khoảng thời gian khác.\n\nBệnh viện tạo ra một chính sách hướng dẫn quy trình giám sát bệnh nhân, bao gồm các nội dung\nsau:\n• Xác định cá nhân giám sát tất cả các giai đoạn chăm sóc bệnh nhân; ví dụ, bác sĩ hoặc\nnhà cung cấp dịch vụ tiên tiến khác\n• Xác định quy trình chuyển giao trách nhiệm giám sát trong những ngày nghỉ; ví dụ, kỳ nghỉ,\nngày ốm, ngày lễ\n• Xác định các chuyên gia tư vấn, bác sĩ trực, người thuê tạm thời hoặc những người khác chịu\ntrách nhiệm\n• Xác định cách chuyển giao trách nhiệm diễn ra và cần có tài liệu nào để đảm bảo\nsự phối hợp và tài liệu về sự tham gia hoặc phạm vi bảo hiểm của họ; ví dụ, khi bệnh nhân\nchuyển từ giai đoạn chăm sóc này sang giai đoạn chăm sóc khác","m":[{"t":"Một cá nhân đủ điều kiện chịu trách nhiệm điều phối việc chăm sóc bệnh nhân có mặt trong tất cả các giai đoạn chăm sóc bệnh nhân nội trú và được xác định trong hồ sơ y tế của bệnh nhân.","b":[]},{"t":"Có một quy trình chuyển giao trách nhiệm điều phối việc chăm sóc.","b":[]},{"t":"Quá trình này xác định cách thức chuyển giao trách nhiệm và sự tham gia hoặc phạm vi bảo hiểm được ghi lại. Xuất viện, Chuyển tuyến và Theo dõi","b":[]}],"sec":"Sự liên tục của việc chăm sóc"},{"c":"ACC.04.00","ch":"ACC","t":"Bệnh viện xây dựng và thực hiện quy trình lập kế hoạch xuất viện và chuyển tuyến dựa trên sự sẵn sàng xuất viện của bệnh nhân.","p":"Việc lập kế hoạch xuất viện sớm và hiệu quả có thể làm giảm nguy cơ tái nhập viện, cải thiện quá trình phục hồi, đảm\nbảo thực hành dùng thuốc an toàn và giúp bệnh nhân và/hoặc gia đình chuẩn bị để có được dịch vụ chăm sóc an toàn\nsau khi xuất viện.\nLập kế hoạch xuất viện là một quy trình được sử dụng để giúp xác định loại dịch vụ và chăm sóc liên tục mà bệnh\nnhân có thể cần sau khi xuất viện. Những cải tiến trong lập kế hoạch xuất viện giúp cải thiện đáng kể kết quả cho\nbệnh nhân khi họ chuyển sang cấp độ chăm sóc tiếp theo. Việc bắt đầu sớm quy trình lập kế hoạch xuất viện là tối\nquan trọng để tối đa hóa kết quả. Quy trình lập kế hoạch xuất viện bao gồm việc đánh giá và xác định nhu cầu của\nbệnh nhân về dịch vụ hoặc chăm sóc liên tục. Nhà cung cấp dịch vụ chăm sóc sức khỏe chính của bệnh nhân sẽ xác\nđịnh mức độ sẵn sàng để giới thiệu hoặc xuất viện.\nViệc giới thiệu hoặc xuất viện bệnh nhân đến một nhà cung cấp dịch vụ chăm sóc sức khỏe bên ngoài bệnh viện, cơ\nsở chăm sóc khác, nhà riêng hoặc gia đình dựa trên tình trạng sức khỏe và mức độ sẵn sàng để xuất viện của bệnh\nnhân. Bệnh viện xác định mọi nhu cầu mà bệnh nhân có thể có về chăm sóc, điều trị và dịch vụ tâm lý xã hội hoặc thể\nchất sau khi xuất viện hoặc chuyển viện. Cần có một quy trình có tổ chức để đảm bảo đáp ứng mọi nhu cầu liên tục.\n\nNhững bệnh nhân không được giới thiệu trực tiếp hoặc chuyển đến một bác sĩ chăm sóc sức khỏe khác sẽ nhận được\nhướng dẫn rõ ràng về địa điểm và cách thức nhận dịch vụ chăm sóc liên tục. Điều này rất cần thiết để đảm bảo đáp\nứng mọi nhu cầu chăm sóc. Hướng dẫn bao gồm tên và địa điểm của các cơ sở chăm sóc liên tục, bất kỳ lần quay lại\nbệnh viện nào để\ntheo dõi và thời điểm cần được chăm sóc khẩn cấp. Quy trình này bao gồm việc chuyển bệnh nhân đến các nguồn\nchăm sóc bên ngoài khu vực khi cần thiết.\n\nBệnh viện bắt đầu lập kế hoạch cho các nhu cầu liên tục ngay từ đầu quá trình chăm sóc. Quy trình lập kế hoạch xuất\nviện bắt đầu bằng đánh giá ban đầu và được cập nhật trong suốt quá trình chăm sóc khi nhu cầu xuất viện của bệnh\nnhân trở nên rõ ràng hơn. Lập kế hoạch xuất viện bao gồm bất kỳ giáo dục đặc biệt nào mà bệnh nhân có thể yêu cầu\nliên quan đến việc chăm sóc liên tục bên ngoài bệnh viện. Bệnh nhân, gia đình bệnh nhân, bác sĩ chăm sóc sức khỏe và\nnhững người khác tham gia vào việc chăm sóc bệnh nhân đều tham gia vào việc lập kế hoạch xuất viện hoặc chuyển\nviện cho bệnh nhân.\n\nBệnh viện thiết lập một phương pháp để xác định mức độ sẵn sàng xuất viện của bệnh nhân. Điều này bao gồm việc\nsử dụng các phương pháp sau:\n• Tiêu chí có liên quan\n• Chỉ định lâm sàng\n• Hướng dẫn/giao thức lâm sàng\n\nBệnh viện thiết lập một quy trình để đảm bảo rằng bệnh nhân nhận được bất kỳ dịch vụ chăm sóc liên tục hoặc hỗ\ntrợ nào mà họ cần sau khi xuất viện. Nhu cầu chăm sóc liên tục bao gồm những điều sau:\n• Giới thiệu đến bác sĩ chuyên khoa\n• Dịch vụ phục hồi chức năng\n\n• Nhập viện vào cơ sở chăm sóc dài hạn\n• Dịch vụ chăm sóc tại nhà\n• Dịch vụ tâm lý\n• Dịch vụ xã hội\n• Vật tư hoặc thiết bị y tế tại nhà\n• Giáo dục liên quan đến nhu cầu chăm sóc liên tục\nBệnh nhân xuất viện về nhà được cung cấp ít nhất các thông tin sau:\n• Tên và địa điểm của một hoặc nhiều địa điểm để chăm sóc liên tục; ví dụ, phòng khám chăm sóc ngoại trú,\ntrung tâm phục hồi chức năng, khoa cấp cứu gần nhất\n• Hướng dẫn bằng văn bản về bất kỳ lần khám hoặc chăm sóc theo dõi nào\n• Khi nào và làm thế nào để nhận được dịch vụ chăm sóc khẩn cấp hoặc cấp cứu\nLập kế hoạch xuất viện và hướng dẫn được ghi lại trong hồ sơ y tế của bệnh nhân và được cung cấp\ncho bệnh nhân bằng văn bản.","m":[{"t":"Việc xuất viện và/hoặc chuyển viện của bệnh nhân phải phù hợp với các tiêu chí, chỉ định hoặc hướng dẫn có liên quan.","b":[]},{"t":"Quy trình lập kế hoạch xuất viện bắt đầu bằng đánh giá ban đầu và bao gồm việc chăm sóc, điều trị, thiết bị và dịch vụ đáp ứng nhu cầu liên tục của bệnh nhân.","b":[]},{"t":"Bệnh nhân không được chuyển viện hoặc chuyển viện trực tiếp được cung cấp tên và địa điểm của một hoặc nhiều địa điểm để tiếp tục chăm sóc.","b":[]},{"t":"Bệnh nhân không được chuyển viện hoặc chuyển viện trực tiếp được cung cấp hướng dẫn, bằng văn bản, về thời điểm quay lại bệnh viện để tiếp tục chăm sóc, điều trị và dịch vụ, cũng như thời điểm và cách thức để được chăm sóc khẩn cấp.","b":[]},{"t":"Bệnh nhân, gia đình khi thích hợp và nhân viên tham gia vào việc chăm sóc bệnh nhân tham gia vào quy trình lập kế hoạch xuất viện.","b":[]},{"t":"Kế hoạch xuất viện và hướng dẫn được ghi lại trong hồ sơ y tế của bệnh nhân và được cung cấp cho bệnh nhân bằng văn bản","b":[]}],"sec":"Xuất viện, Chuyển tuyến và Theo dõi"},{"c":"ACC.04.01","ch":"ACC","t":"Quy trình xuất viện của bệnh viện bao gồm việc giáo dục bệnh nhân và gia đình liên quan đến nhu cầu liên tục của bệnh nhân về việc chăm sóc, điều trị và dịch vụ liên tục.","p":"Giáo dục bệnh nhân và gia đình là một thành phần quan trọng của kế hoạch xuất viện và hỗ trợ bệnh nhân trở lại\nmức chức năng trước đó và duy trì sức khỏe tối ưu.\n\nQuy trình xuất viện giải quyết nhu cầu giáo dục của bệnh nhân và gia đình về cách quản lý nhu cầu chăm sóc liên\ntục của bệnh nhân tại nhà hoặc giáo dục về cách hỗ trợ nhu cầu chăm sóc liên tục của bệnh nhân trong một môi\ntrường khác. Các tài liệu và quy trình chuẩn hóa được sử dụng để giáo dục bệnh nhân về các chủ đề liên quan\nđến việc chăm sóc và điều trị liên tục của họ sau khi xuất viện. Giáo dục bệnh nhân và hướng dẫn theo dõi được\ncung cấp cho bệnh nhân dưới hình thức và ngôn ngữ mà bệnh nhân hiểu được.\n\nDựa trên nhu cầu chăm sóc liên tục được xác định của bệnh nhân, giáo dục và hướng dẫn xuất viện có thể bao\ngồm nhưng không giới hạn ở các chủ đề sau:\n• Xem xét tất cả các loại thuốc sẽ dùng tại nhà\n• Sử dụng an toàn và hiệu quả tất cả các loại thuốc, bao gồm các tác dụng phụ tiềm ẩn của thuốc\n• Tương tác tiềm ẩn giữa thuốc theo toa và các loại thuốc khác (bao gồm các chế phẩm không kê đơn) và thực\nphẩm\n• Chế độ ăn uống và dinh dưỡng\n• Quản lý cơn đau\n\n• Sử dụng thiết bị y tế an toàn và hiệu quả\n• Các hoạt động và dịch vụ phục hồi chức năng\n\nGiáo dục bệnh nhân và hướng dẫn theo dõi được cung cấp cho bệnh nhân theo hình thức và ngôn ngữ mà\nbệnh nhân hiểu được. Khuyến cáo nên cung cấp giáo dục và hướng dẫn bằng văn bản cho bệnh nhân và gia\nđình, để họ có thể tham khảo các tài liệu này khi cần. Tuy nhiên, không phải tất cả bệnh nhân và gia đình đều\ncó kỹ năng đọc cơ bản. Nếu giáo dục và hướng dẫn được cung cấp theo các hình thức khác, điều này phải\nđược ghi lại trong hồ sơ y tế của bệnh nhân. Giáo dục và hướng dẫn có thể được cung cấp theo các hình\nthức sau:\n• Bằng văn bản (phương pháp được khuyến nghị)\n• Bằng lời nói\n• Phương tiện truyền thông (ví dụ: video, ảnh, biểu tượng)","m":[{"t":"Bệnh nhân và gia đình được cung cấp danh sách thuốc đầy đủ bằng văn bản để dùng tại nhà và được giáo dục về cách sử dụng an toàn, bao gồm những thông tin sau:","b":["Tác dụng phụ tiềm ẩn","Tương tác tiềm ẩn giữa các loại thuốc","Tương tác tiềm ẩn giữa thuốc và thực phẩm"]},{"t":"Bệnh nhân và gia đình được giáo dục về chế độ ăn uống và dinh dưỡng hợp lý.","b":[]},{"t":"Bệnh nhân và gia đình được giáo dục về cách kiểm soát cơn đau. (Xem thêm COP.07.00, ME 3)","b":[]},{"t":"Bệnh nhân và gia đình được giáo dục về cách sử dụng an toàn và hiệu quả các thiết bị y tế và các hoạt động và dịch vụ phục hồi chức năng.","b":[]},{"t":"Giáo dục cho bệnh nhân và gia đình được ghi lại trong hồ sơ y tế của bệnh nhân và bao gồm những thông tin sau:","b":["Thông tin và giáo dục nào đã được cung cấp","Thông tin và giáo dục được cung cấp như thế nào (ví dụ, bằng văn bản, bằng lời nói, bằng trình diễn)","Xác nhận rằng bệnh nhân và/hoặc gia đình đã hiểu thông tin và giáo dục được cung cấp (Xem thêm PCC.04.01, ME 2 và 3)"]}],"sec":"Xuất viện, Chuyển tuyến và Theo dõi"},{"c":"ACC.04.02","ch":"ACC","t":"Tóm tắt xuất viện đầy đủ được chuẩn bị cho tất cả bệnh nhân và được đưa vào hồ sơ y tế của bệnh nhân.","p":"Tóm tắt xuất viện cung cấp tổng quan về việc chăm sóc bệnh nhân và được sử dụng bởi các nhà cung cấp dịch vụ\nchăm sóc sức khỏe chăm sóc bệnh nhân sau khi xuất viện.\n\nTóm tắt về việc chăm sóc bệnh nhân được chuẩn bị trước khi xuất viện. Bất kỳ cá nhân đủ điều kiện nào cũng có\nthể biên soạn tóm tắt xuất viện, chẳng hạn như bác sĩ của bệnh nhân hoặc nhân viên nội trú. Một bản sao tóm tắt\nxuất viện được cung cấp cho bác sĩ chịu trách nhiệm chăm sóc liên tục hoặc theo dõi bệnh nhân.\n\nMột bản sao sẽ được cung cấp cho bệnh nhân khi chính sách của bệnh viện chỉ định hoặc khi luật pháp hoặc quy\nđịnh của địa phương yêu cầu. Khi không biết nhà cung cấp chịu trách nhiệm chăm sóc theo dõi (ví dụ: bệnh nhân\nđến từ một khu vực hoặc quốc gia khác), một bản sao tóm tắt xuất viện sẽ được cung cấp cho bệnh nhân hoặc gia\nđình. Kỳ vọng là bệnh nhân cung cấp bản sao tóm tắt xuất viện của mình cho bác sĩ chăm sóc chính hoặc bác sĩ đa\nkhoa chịu trách nhiệm chăm sóc họ.\n\nMột bản sao tóm tắt xuất viện được đưa vào hồ sơ y tế của bệnh nhân.\n\nBệnh viện có quy trình cung cấp bản sao tóm tắt xuất viện cho nhà cung cấp dịch vụ chăm sóc sức khỏe chịu trách\nnhiệm chăm sóc liên tục hoặc theo dõi bệnh nhân.\n\nBệnh viện đã xác định các tình huống khi bệnh nhân sẽ được cung cấp một bản sao tóm tắt xuất viện. Các ví dụ\nbao gồm:\n• Khi chính sách của bệnh viện yêu cầu\n• Khi luật pháp hoặc quy định của địa phương yêu cầu\n• Khi không rõ nhà cung cấp dịch vụ chăm sóc sức khỏe chịu trách nhiệm chăm sóc theo dõi bệnh nhân\n\nTóm tắt bao gồm:\n• Lý do nhập viện, chẩn đoán và bệnh đi kèm\n• Các phát hiện quan trọng về thể chất và các phát hiện khác\n• Các thủ thuật chẩn đoán và điều trị đã thực hiện\n• Thuốc tại thời điểm xuất viện, bao gồm ngày/giờ dùng thuốc cuối cùng\n• Tất cả các loại thuốc cần dùng tại nhà\n• Thiết bị điều trị tại thời điểm xuất viện (ví dụ: máy phun khí dung, máy đo đường huyết, thiết bị hỗ trợ đi lại)\n• Tình trạng của bệnh nhân tại thời điểm xuất viện (ví dụ: \"tình trạng đã cải thiện\", \"bệnh nhân ở tình trạng ban\nđầu\")\n• Hướng dẫn theo dõi","m":[{"t":"Tóm tắt xuất viện được chuẩn bị bởi một cá nhân đủ điều kiện.","b":[]},{"t":"Tóm tắt xuất viện bao gồm ít nhất những thông tin sau:","b":["Lý do nhập viện, chẩn đoán và bệnh đi kèm","Các phát hiện quan trọng về thể chất và các phát hiện khác","Các thủ thuật chẩn đoán và điều trị đã thực hiện","Thuốc tại thời điểm xuất viện, bao gồm ngày/giờ dùng liều cuối cùng trong thời gian nằm viện","Tất cả các loại thuốc cần dùng tại nhà","Thiết bị điều trị tại thời điểm xuất viện","Tình trạng của bệnh nhân tại thời điểm xuất viện","Hướng dẫn theo dõi"]},{"t":"Một bản sao tóm tắt xuất viện được cung cấp cho nhà cung cấp dịch vụ chăm sóc sức khỏe chịu trách nhiệm về việc chăm sóc liên tục hoặc theo dõi của bệnh nhân.","b":[]},{"t":"Bệnh nhân hoặc người chăm sóc được cung cấp một bản sao tóm tắt xuất viện.","b":[]},{"t":"Một bản sao tóm tắt xuất viện đã hoàn thành được đưa vào hồ sơ y tế của bệnh nhân tại thời điểm xuất viện.","b":[]}],"sec":"Xuất viện, Chuyển tuyến và Theo dõi"},{"c":"ACC.04.03","ch":"ACC","t":"Chăm sóc khẩn cấp được ghi chép lại.","p":"Chăm sóc cấp cứu được ghi chép lại để đảm bảo tính liên tục của việc chăm sóc và cho phép các nhà cung\ncấp ở cấp độ chăm sóc tiếp theo hiểu được các dịch vụ cấp cứu được cung cấp.\n\nHồ sơ của mỗi bệnh nhân được chăm sóc cấp cứu bao gồm thời gian đến và rời đi. Thông tin này được ghi\nlại cho tất cả các bệnh nhân khoa cấp cứu, bao gồm cả những bệnh nhân được xuất viện khỏi bệnh viện,\nđược chuyển đến một cơ sở khác hoặc được nhận vào làm bệnh nhân nội trú. Thời gian rời đi có thể là khi\nbệnh nhân rời khỏi khoa cấp cứu để về nhà hoặc đến một cơ sở khác, hoặc thời điểm bệnh nhân được\nchuyển đến một đơn vị khác làm bệnh nhân nội trú. Đối với những bệnh nhân được xuất viện khỏi khoa\ncấp cứu, hồ sơ y tế bao gồm các kết luận sau khi hoàn thành việc điều trị cấp cứu, tình trạng của bệnh\nnhân khi xuất viện và hướng dẫn chăm sóc theo dõi.","m":[{"t":"Hồ sơ bệnh án của tất cả bệnh nhân cấp cứu bao gồm thời gian đến và đi.","b":[]},{"t":"Hồ sơ bệnh án của bệnh nhân xuất viện từ khoa cấp cứu bao gồm kết luận sau khi hoàn tất quá trình điều trị.","b":[]},{"t":"Hồ sơ bệnh án của bệnh nhân xuất viện từ khoa cấp cứu bao gồm tình trạng bệnh nhân khi xuất viện.","b":[]},{"t":"Hồ sơ bệnh án của bệnh nhân xuất viện từ khoa cấp cứu bao gồm mọi hướng dẫn chăm sóc theo dõi.","b":[]}],"sec":"Xuất viện, Chuyển tuyến và Theo dõi"},{"c":"ACC.04.04","ch":"ACC","t":"Hồ sơ y tế chứa thông tin bệnh nhân.","p":"Hồ sơ bệnh nhân cung cấp bản tóm tắt về tình trạng và phương pháp điều trị của bệnh nhân và có sẵn cho tất cả các\nthành viên trong nhóm chăm sóc sức khỏe của bệnh nhân trong suốt quá trình chăm sóc. Hồ sơ bệnh nhân cung cấp\n\"ảnh chụp nhanh\" về bệnh nhân và quá trình chăm sóc của họ.\n\nBệnh viện tạo hồ sơ bệnh nhân hoặc các bản tóm tắt ngắn gọn tương tự cho tất cả bệnh nhân, bao gồm cả bệnh nhân\nnội trú và ngoại trú, như một phần của hồ sơ y tế của bệnh nhân. Hồ sơ giúp các nhà cung cấp dịch vụ chăm sóc\nsức khỏe có thể nhanh chóng và dễ dàng cập nhật thông tin quan trọng, đặc biệt là khi có nhiều nhà cung cấp tham gia\nvào\nviệc chăm sóc bệnh nhân. Hồ sơ bệnh nhân đặc biệt hữu ích khi bệnh nhân có chẩn đoán và chăm sóc phức tạp, nhiều\nvấn đề hoặc nhiều nhóm chăm sóc. Vì sự cố chăm sóc sức khỏe là động, nên hồ sơ bệnh nhân phải được cập nhật và\ncập nhật thông tin bệnh nhân khi có bất kỳ thay đổi nào xảy ra. Tóm tắt hồ sơ phải có trong một tài liệu để bất kỳ nhà\ncung cấp dịch vụ chăm sóc sức khỏe nào cũng có thể truy cập hiệu quả.\n\nHồ sơ bệnh nhân là bắt buộc đối với cả hồ sơ y tế điện tử và bản cứng.\n\nQuy trình tạo hồ sơ bệnh nhân bao gồm việc xác định thông tin nào là một phần của hồ sơ bệnh nhân. Ví dụ về thông\ntin như vậy bao gồm:\n• Tuổi, cân nặng, chiều cao của bệnh nhân\n• Danh sách các vấn đề đang diễn ra\n• Tiền sử bệnh lý và phẫu thuật trước đây\n• Thông tin điều trị hiện tại\n• Dị ứng\n\nNhững cân nhắc bổ sung bao gồm tạo một định dạng dễ dàng để các bác sĩ lâm sàng truy xuất, xem xét và đánh giá quy\ntrình để xác minh rằng hồ sơ đáp ứng nhu cầu của các bác sĩ lâm sàng.\n\nHồ sơ bệnh nhân có thể được cấu trúc khác nhau hoặc chứa thông tin khác nhau giữa các lĩnh vực chăm sóc để đáp\nứng nhu cầu của bác sĩ lâm sàng; tuy nhiên, hồ sơ phải nhất quán trong các lĩnh vực chăm sóc, như trong các ví dụ sau:\n• Hồ sơ bệnh nhân nội trú và ngoại trú có thể được cấu trúc khác nhau, nhưng tất cả hồ sơ bệnh nhân nội trú và\nngoại trú đều nhất quán.\n• Hồ sơ bệnh nhân nội khoa và ngoại khoa có thể được cấu trúc khác nhau nhưng tất cả hồ sơ bệnh nhân ngoại\nkhoa và ngoại khoa đều nhất quán.\n• Hồ sơ bệnh nhân phục hồi chức năng tâm thần và thể chất có thể được cấu trúc khác nhau, nhưng tất cả hồ sơ\nphục hồi chức năng thể chất của bệnh nhân tâm thần đều nhất quán.","m":[{"t":"Tất cả hồ sơ y tế của bệnh nhân đều có hồ sơ bệnh nhân hoặc bản tóm tắt tương tự.","b":[]},{"t":"Bệnh viện xác định thông tin cần thiết để đưa vào hồ sơ.","b":[]},{"t":"Hồ sơ bệnh nhân dễ truy cập và xem xét và nhất quán trong các lĩnh vực chăm sóc.","b":[]},{"t":"Quy trình được đánh giá để đảm bảo rằng việc triển khai nhất quán với chính sách và cung cấp cho các bác sĩ lâm sàng bản tóm tắt chính xác về bệnh nhân.","b":[]}],"sec":"Xuất viện, Chuyển tuyến và Theo dõi"},{"c":"ACC.04.05","ch":"ACC","t":"Bệnh viện có quy trình quản lý bệnh nhân rời khỏi bệnh viện trái với lời khuyên của bác sĩ.","p":"Bệnh nhân rời đi mà không có lời khuyên y khoa có nguy cơ được điều trị không đầy đủ, có thể dẫn đến tổn hại\nvĩnh viễn hoặc tử vong. Bệnh viện phải có quy trình quản lý bệnh nhân rời đi mà không có lời khuyên y khoa và\nthông báo cho họ về những rủi ro liên quan đến quyết định này.\n\n“Rời đi mà không có lời khuyên y khoa” có nghĩa là rời khỏi bệnh viện sau khi đã hoàn tất quá trình khám và\nđã có khuyến nghị về kế hoạch điều trị. Rời đi mà không có lời khuyên y khoa cũng bao gồm những bệnh nhân\nkhông hoàn tất hoặc không quay lại để điều trị phức tạp hoặc cứu sống trong môi trường ngoại trú.\n\nBệnh nhân nội trú và ngoại trú, bao gồm cả bệnh nhân từ khoa cấp cứu, có quyền từ chối điều trị y khoa và rời\nkhỏi bệnh viện mà không có lời khuyên y khoa. Tuy nhiên, những bệnh nhân này có thể có nguy cơ được điều\ntrị không đầy đủ, có thể dẫn đến tổn hại vĩnh viễn hoặc tử vong.\n\nKhi một bệnh nhân đủ năng lực yêu cầu rời khỏi bệnh viện mà không có sự chấp thuận của bác sĩ, những rủi ro\nphải được giải thích bởi nhà cung cấp đề xuất kế hoạch điều trị hoặc người được họ chỉ định, và cuộc trò chuyện\nphải được ghi lại trong hồ sơ y tế. Nếu bệnh nhân cho phép, phải tuân theo các thủ tục xuất viện thông\nthường. Bệnh nhân rời đi mà không có lời khuyên y khoa không được rời khỏi cơ sở mà không nhận được thông\ntin về việc chăm sóc y tế của họ. Các nhà cung cấp dịch vụ chăm sóc sức khỏe cố gắng xác định lý do tại sao bệnh\nnhân chọn rời đi mà không có lời khuyên y khoa để cải thiện giao tiếp và xác định những cải tiến tiềm năng cho\nquy trình. Khi bệnh nhân rời khỏi bệnh viện mà không có lời khuyên y khoa mà không thông báo cho bất kỳ ai\nhoặc không quay lại để điều trị, bệnh viện phải cố gắng liên hệ với bệnh nhân để thông báo cho họ về những rủi\nro tiềm ẩn.\n\nNếu bệnh nhân có nhà cung cấp dịch vụ chăm sóc chính được ghi nhận, họ phải được thông báo về quyết định\nrời đi mà không có lời khuyên y khoa của bệnh nhân. Khi áp dụng, bệnh viện sẽ báo cáo các trường hợp mắc\nbệnh truyền nhiễm và cung cấp thông tin liên quan đến những bệnh nhân có thể gây hại cho bản thân hoặc người\nkhác cho các cơ quan y tế địa phương và quốc gia khi cần thiết.\n\nNếu bệnh nhân có nguy cơ tự gây hại hoặc gây hại cho người khác, bệnh viện phải hạn chế bệnh nhân rời đi\nnếu luật pháp và quy định của địa phương cho phép.\n\nBệnh viện có thể xây dựng quy trình cho phép bệnh nhân rời khỏi bệnh viện trong một khoảng thời gian xác định\n(chẳng hạn như \"giấy phép\" cuối tuần) nếu được bác sĩ điều trị của bệnh nhân chấp thuận và luật pháp và quy\nđịnh của địa phương cho phép. Việc vắng mặt tạm thời như vậy không được coi là rời đi mà không có lời khuyên\ny khoa.\n\nBệnh viện thiết kế quy trình này để phù hợp với luật pháp và quy định hiện hành. Quy trình quản lý bệnh nhân\nrời đi trái với lời khuyên của bác sĩ bao gồm những nội dung sau:\n•\nBệnh nhân nội trú rời đi có hoặc không thông báo cho nhân viên bệnh viện\n•\nBệnh nhân bỏ trốn\n•\nBệnh nhân đang điều trị phức tạp nhưng không hoàn thành hoặc không quay lại để điều trị (“không xuất\nhiện”)\nQuy trình bao gồm liên hệ với những cá nhân sau:\n•\nBệnh nhân (nếu có thể) để thông báo cho họ về những rủi ro tiềm ẩn khi rời đi trái với lời khuyên của bác sĩ\n•\nGia đình hoặc người chăm sóc bệnh nhân, nếu có\n•\nNhà cung cấp dịch vụ chăm sóc chính của bệnh nhân nếu biết\n•\nCơ quan y tế địa phương và quốc gia, nếu cần, nếu bệnh nhân mắc bệnh truyền nhiễm đã biết hoặc nghi ngờ\n•\nCơ quan y tế địa phương, nếu cần, nếu bệnh nhân có nguy cơ gây hại cho bản thân hoặc người khác\n\nQuy trình này xác định kỳ vọng về việc ghi lại “rời đi trái với lời khuyên của bác sĩ”, bệnh nhân bỏ trốn và không\nxuất hiện.\n\nQuy trình bao gồm những nội dung sau:\n• Cho phép bệnh nhân rời đi trong một khoảng thời gian xác định trong quá trình điều trị đã lên kế hoạch\n• Xác định các tiêu chí lâm sàng để bệnh nhân rời đi. Ví dụ về các tiêu chí bao gồm:\no Tình trạng thể chất\no Tình trạng tinh thần\no Khả năng tự chăm sóc của bệnh nhân hoặc khả năng chăm sóc bệnh nhân của gia đình\n• Bao gồm nhóm điều trị, bệnh nhân và gia đình bệnh nhân (nếu có) trong quyết định","m":[{"t":"Có một quy trình bằng văn bản để quản lý những bệnh nhân rời đi mà không có lời khuyên y khoa; quy trình này bao gồm những nội dung sau:","b":["Bệnh nhân nội trú rời đi có hoặc không thông báo cho nhân viên bệnh viện","Bệnh nhân bỏ trốn","Bệnh nhân đang được điều trị phức tạp nhưng không hoàn thành hoặc không quay lại để điều trị (“không xuất hiện”)","Yêu cầu về hồ sơ"]},{"t":"Có một quy trình để thông báo cho bệnh nhân về những rủi ro y khoa do điều trị không đầy đủ.","b":[]},{"t":"Bệnh nhân được xuất viện theo quy trình xuất viện của bệnh viện.","b":[]},{"t":"Có một quy trình để thông báo cho bác sĩ chăm sóc chính của bệnh nhân nếu bệnh nhân rời đi mà không có lời khuyên y khoa.","b":[]},{"t":"Quy trình này phù hợp với luật pháp và quy định hiện hành, bao gồm các yêu cầu báo cáo các trường hợp mắc bệnh truyền nhiễm và khi bệnh nhân có thể gây nguy hiểm cho chính họ hoặc người khác.","b":[]},{"t":"Khi phù hợp với luật pháp và quy định của khu vực, bệnh viện sẽ xây dựng một quy trình cho phép bệnh nhân rời khỏi bệnh viện trong quá trình điều trị đã lên kế hoạch trong một khoảng thời gian xác định Chuyển bệnh nhân","b":[]}],"sec":"Xuất viện, Chuyển tuyến và Theo dõi"},{"c":"ACC.05.00","ch":"ACC","t":"Bệnh viện có quy trình chuyển bệnh nhân đến các tổ chức chăm sóc sức khỏe khác dựa trên tình trạng của bệnh nhân và khả năng đáp ứng các nhu cầu đó của bệnh viện.","p":"Việc chuyển bệnh nhân đến một tổ chức bên ngoài dựa trên tình trạng của bệnh nhân và nhu cầu tiếp tục được chăm sóc\nsức khỏe. Các tiêu chí giúp xác định thời điểm cần chuyển bệnh nhân để đảm bảo đáp ứng được nhu cầu của bệnh nhân.\n\nChuyển bệnh nhân có thể là để đáp ứng nhu cầu của bệnh nhân. Các ví dụ về nhu cầu bao gồm:\n•\nTư vấn và điều trị chuyên khoa\n•\nDịch vụ khẩn cấp\n•\nDịch vụ ít chuyên sâu hơn (như chăm sóc bán cấp hoặc phục hồi chức năng dài hạn)\n•\nYêu cầu của bệnh nhân hoặc gia đình\n\nBệnh viện phải xác định xem tổ chức tiếp nhận có cung cấp dịch vụ đáp ứng nhu cầu của bệnh nhân và có đủ năng lực tiếp\nnhận bệnh nhân hay không. Việc xác định trước này đảm bảo tính liên tục của việc chăm sóc và nhu cầu chăm sóc của bệnh\nnhân sẽ được đáp ứng. Các yêu cầu chuyển bệnh nhân được mô tả trong các thỏa thuận hoặc liên kết chính thức hoặc\nkhông chính thức. Tuy nhiên, việc chuyển bệnh nhân đến các dịch vụ hoặc phương pháp điều trị chuyên khoa khác mà\nkhông có thỏa thuận chính thức hoặc không chính thức.\n\nCần có một quy trình nhất quán cho bệnh nhân để đảm bảo bệnh nhân được chuyển giữa các tổ chức chăm sóc sức khỏe\nmột cách an toàn.\n\nTình trạng và tình trạng của bệnh nhân quyết định trình độ cần thiết của nhân viên theo dõi bệnh nhân và loại thiết\nbị y tế cần thiết trong quá trình chuyển viện.\n\nBệnh viện đánh giá chất lượng và tính an toàn của quá trình chuyển viện để đảm bảo bệnh nhân được chuyển viện\nvới đội ngũ nhân viên có trình độ và thiết bị y tế phù hợp với tình trạng của bệnh nhân.\n\nQuy trình chuyển bệnh nhân nêu rõ những điều sau:\n•\nTrách nhiệm được chuyển giao như thế nào và khi nào giữa các nhà cung cấp và tổ chức\n•\nTiêu chí về thời điểm cần chuyển giao để đáp ứng nhu cầu của bệnh nhân\n•\nAi chịu trách nhiệm về bệnh nhân trong quá trình chuyển giao\n•\nTrình độ của nhân viên chăm sóc bệnh nhân trong quá trình chuyển giao\n•\nCần những loại thuốc, vật tư và thiết bị y tế nào trong quá trình vận chuyển\n•\nCơ chế theo dõi cung cấp thông tin về tình trạng của bệnh nhân trong quá trình chuyển giao và khi đến tổ chức\ntiếp nhận\n•\nCần làm gì khi không thể chuyển sang nguồn chăm sóc khác","m":[{"t":"D Bệnh viện xây dựng một quy trình chuyển giao bằng văn bản dựa trên nhu cầu chăm sóc liên tục của bệnh nhân và đảm bảo rằng tổ chức tiếp nhận đáp ứng được nhu cầu của bệnh nhân được chuyển giao. (Xem thêm ACC.02.02, ME 4; ACC.03.00, ME1; GLD.06.00, ME 4)","b":[]},{"t":"Quy trình chuyển giao đề cập đến cách thức và thời điểm trách nhiệm chăm sóc liên tục được chuyển giao cho một nhà cung cấp khác.","b":[]},{"t":"Quy trình chuyển giao xác định người chịu trách nhiệm theo dõi bệnh nhân trong quá trình chuyển giao và trình độ của nhân viên cần thiết cho loại bệnh nhân được chuyển giao.","b":[]},{"t":"Quy trình chuyển giao xác định các loại thuốc, vật tư và thiết bị y tế cần thiết trong quá trình vận chuyển.","b":[]},{"t":"Quy trình chuyển giao giải quyết cơ chế theo dõi cung cấp thông tin về tình trạng của bệnh nhân khi đến tổ chức tiếp nhận.","b":[]},{"t":"Quy trình chuyển giao giải quyết các tình huống không thể chuyển giao.","b":[]}],"sec":"Chuyển bệnh nhân"},{"c":"ACC.05.01","ch":"ACC","t":"Tổ chức tiếp nhận được cung cấp bản tóm tắt bằng văn bản về tình trạng lâm sàng của bệnh nhân và các biện pháp can thiệp do bệnh viện cung cấp, và quy trình này được ghi lại trong hồ sơ y tế của bệnh nhân.","p":"Để đảm bảo tính liên tục của việc chăm sóc, thông tin bệnh nhân được chuyển giao cùng với bệnh nhân.\n\nTổ chức tiếp nhận cần hiểu bất kỳ dịch vụ chăm sóc bệnh nhân nào được cung cấp trước và trong quá trình chuyển\ngiao. Nếu không có thông tin này, có nguy cơ thông tin quan trọng của bệnh nhân sẽ không được truyền đạt hoặc các\nbiện pháp can thiệp, phương pháp điều trị hoặc thuốc được lặp lại hoặc bỏ sót. Một bản sao của bản tóm tắt lâm\nsàng hoặc xuất viện được cung cấp cho tổ chức tiếp nhận cùng với bệnh nhân. Hồ sơ bệnh án của bệnh nhân có chứa\ntài liệu về việc chuyển giao.\n\nBản tóm tắt lâm sàng hoặc xuất viện bằng văn bản bao gồm ít nhất những nội dung sau:\n• Tình trạng hoặc tình trạng lâm sàng của bệnh nhân\n• Các thủ thuật và biện pháp can thiệp khác được cung cấp\n• Nhu cầu liên tục của bệnh nhân và lý do chuyển giao\n\nHồ sơ chuyển giao bao gồm những nội dung sau:\n• Tên của tổ chức chăm sóc sức khỏe và tên của cá nhân đồng ý tiếp nhận bệnh nhân\n• Lý do chuyển giao\n\nTiếp cận dịch vụ chăm sóc và tính\nliên tục của dịch vụ chăm sóc\n•\nBất kỳ thay đổi nghiêm trọng nào về tình trạng hoặc tình trạng của bệnh nhân trong quá trình chuyển viện\n•\nBất kỳ tài liệu nào khác theo yêu cầu của chính sách bệnh viện (ví dụ: chữ ký của y tá tiếp nhận hoặc\nbác sĩ, tên của cá nhân theo dõi bệnh nhân trong quá trình vận chuyển)\nCác y\nác y\nác y\nác yếu t\nu t\nu t\nu tố có th\ncó th\ncó th\ncó thể đo l\nđo l\nđo l\nđo lường c\nng c\nng c\nng của ACC\na ACC\na ACC\na ACC.05.01\n.05.01\n.05.01\n.05.01\n1. Một bản tóm tắt lâm sàng bằng văn bản được chuyển cùng với bệnh nhân và bao gồm ít nhất những\nthông tin sau:\n•\nTình trạng hoặc tình trạng của bệnh nhân\n•\nCác thủ thuật và can thiệp khác được cung cấp\n•\nNhu cầu liên tục của bệnh nhân và lý do chuyển viện\n2. D Tài liệu chuyển viện bao gồm ít nhất những thông tin sau:\n•\nTên của nhà cung cấp dịch vụ và tên của cá nhân đồng ý tiếp nhận bệnh nhân\n•\nLý do chuyển viện\n•\nNhững thay đổi về tình trạng hoặc tình trạng của bệnh nhân\n•\nTài liệu khác theo yêu cầu của chính sách bệnh viện\nVận chuyển","m":[],"sec":"Chuyển bệnh nhân"},{"c":"ACC.06.00","ch":"ACC","t":"Dịch vụ vận chuyển của bệnh viện tuân thủ các luật và quy định có liên quan và đáp ứng các yêu cầu về vận chuyển an toàn, chất lượng cao.","p":"Bệnh nhân có thể cần được vận chuyển tại thời điểm xuất viện hoặc chuyển viện; bệnh viện có trách nhiệm đánh giá nhu\ncầu vận chuyển của bệnh nhân và sắp xếp phương tiện vận chuyển an toàn khi cần thiết.\n\nBệnh viện có trách nhiệm đánh giá nhu cầu vận chuyển của bệnh nhân và đảm bảo vận chuyển an toàn cho những bệnh\nnhân cần hỗ trợ. Các dịch vụ vận chuyển có thể được cung cấp bởi các bên sau:\n•\nDịch vụ do bệnh viện sở hữu\n•\nDịch vụ vận chuyển theo hợp đồng\n•\nBộ Y tế\n•\nCơ quan khác\nBệnh viện có quy trình đánh giá nhu cầu vận chuyển của bệnh nhân tại thời điểm xuất viện hoặc chuyển viện.\nNhu cầu vận chuyển của bệnh nhân có thể thay đổi từ khi nhập viện đến khi xuất viện. Ví dụ về những thay đổi này có thể\nbao gồm thay đổi về tình trạng thể chất hoặc tinh thần của họ hoặc sử dụng thuốc an thần trong quá trình phẫu thuật trong\nngày.\n\nThiết bị, vật tư và thuốc cần thiết để vận chuyển được xác định theo loại bệnh nhân và tình trạng của bệnh nhân tại thời\nđiểm vận chuyển. Bệnh viện xác định trình độ của nhân viên và mức độ theo dõi cần thiết dựa trên loại bệnh nhân và tình\ntrạng của bệnh nhân tại thời điểm vận chuyển.\n\nBệnh viện xác định các tình huống vận chuyển có nguy cơ lây nhiễm và thực hiện các chiến lược để giảm nguy cơ lây nhiễm.\n\nBệnh viện đảm bảo rằng các dịch vụ vận chuyển đáp ứng mọi luật và quy định hiện hành liên quan đến hoạt động, tình trạng\nvà bảo trì của dịch vụ. Bệnh viện đánh giá chất lượng và sự an toàn của dịch vụ vận chuyển, bao gồm cả khiếu nại về dịch vụ\nvận chuyển.\n\nTùy thuộc vào chính sách của bệnh viện và luật pháp và quy định của khu vực, chi phí vận chuyển có thể do bệnh viện chịu\ntrách nhiệm hoặc không.\n\nBệnh viện có quy trình đánh giá nhu cầu vận chuyển của bệnh nhân. Quy trình này bao gồm những nội dung sau:\n•\nXác định bệnh nhân nào cần được vận chuyển\n\n•\nXác định loại phương tiện vận chuyển nào là cần thiết (ví dụ: xe cứu thương, máy bay, phương tiện\nkhác)\n•\nXác định trình độ của nhân viên để vận chuyển\n•\nXác định thiết bị, vật tư và thuốc nào là cần thiết để vận chuyển\n•\nXác định tiêu chí theo dõi bệnh nhân trong quá trình vận chuyển\n\nBệnh viện có quy trình đảm bảo an toàn và chất lượng của dịch vụ vận chuyển. Bao gồm:\n•\nĐảm bảo rằng dịch vụ vận chuyển tuân thủ luật pháp và quy định của địa phương và khu vực\n•\nXác định rủi ro nhiễm trùng và triển khai các chiến lược để giảm rủi ro nhiễm trùng (dịch vụ vận chuyển\nlà một phần của chương trình phòng ngừa và kiểm soát nhiễm trùng của bệnh viện)\n•\nĐánh giá chất lượng và tính an toàn của các dịch vụ do bệnh viện hoặc các bên khác cung cấp, bao gồm\ntiếp nhận, đánh giá và phản hồi khiếu nại về dịch vụ vận chuyển được cung cấp hoặc sắp xếp\n\nLưu ý: Nếu bệnh viện không cung cấp dịch vụ vận chuyển, bệnh viện có quy trình cung cấp phản hồi về tính\nan toàn và chất lượng cho tổ chức có trách nhiệm.","m":[{"t":"Quy trình xuất viện hoặc chuyển bệnh nhân bao gồm đánh giá nhu cầu vận chuyển bệnh nhân.","b":[]},{"t":"Các dịch vụ vận chuyển, bao gồm các dịch vụ theo hợp đồng và phương tiện vận chuyển do bệnh viện sở hữu phải đáp ứng các luật và quy định có liên quan và các yêu cầu của bệnh viện về vận chuyển an toàn và chất lượng cao.","b":[]},{"t":"Tất cả các phương tiện được sử dụng để vận chuyển, theo hợp đồng hoặc do bệnh viện sở hữu, đều tuân thủ chương trình phòng ngừa và kiểm soát nhiễm trùng của bệnh viện.","b":[]},{"t":"Tất cả các phương tiện được sử dụng để vận chuyển, theo hợp đồng hoặc do bệnh viện sở hữu, đều có thiết bị y tế, vật tư và thuốc phù hợp để đáp ứng nhu cầu của bệnh nhân được vận chuyển.","b":[]},{"t":"Việc vận chuyển được cung cấp hoặc sắp xếp phải phù hợp với nhu cầu và tình trạng của bệnh nhân.","b":[]},{"t":"Có một quy trình để giám sát chất lượng và sự an toàn của việc vận chuyển do bệnh viện cung cấp hoặc sắp xếp, bao gồm quy trình khiếu nại. Đánh giá bệnh nhân (AOP) Đánh giá bệnh nhân (AOP) Tổng quan Mục tiêu của đánh giá là xác định việc chăm sóc, điều trị và các dịch vụ sẽ đáp ứng nhu cầu ban đầu và tiếp tục của bệnh nhân. Một quy trình đánh giá bệnh nhân hiệu quả sẽ đưa ra quyết định về nhu cầu điều trị của bệnh nhân đối với việc chăm sóc khẩn cấp, theo yêu cầu hoặc theo kế hoạch, ngay cả khi tình trạng của bệnh nhân thay đổi. Đánh giá bệnh nhân là một quy trình liên tục, năng động diễn ra tại nhiều cơ sở, khoa và phòng khám nội trú và ngoại trú. Đánh giá bệnh nhân bao gồm ba quy trình chính:","b":[]},{"t":"Thu thập thông tin và dữ liệu về tình trạng thể chất, tâm lý và xã hội của bệnh nhân, cũng như tiền sử sức khỏe","b":[]},{"t":"Phân tích dữ liệu và thông tin, bao gồm kết quả xét nghiệm trong phòng thí nghiệm, chẩn đoán hình ảnh, và theo dõi sinh lý, để xác định nhu cầu chăm sóc sức khỏe của bệnh nhân","b":[]},{"t":"Xây dựng kế hoạch chăm sóc để đáp ứng nhu cầu đã xác định của bệnh nhân Cần phải đánh giá lại nhu cầu của bệnh nhân trong suốt quá trình chăm sóc, điều trị và dịch vụ. Đánh giá lại là chìa khóa để hiểu được phản ứng của bệnh nhân đối với việc chăm sóc, điều trị và các dịch vụ được cung cấp và rất cần thiết để xác định xem các quyết định chăm sóc có phù hợp và hiệu quả hay không. Các hoạt động đánh giá có thể khác nhau giữa các bối cảnh, theo định nghĩa của các nhà lãnh đạo bệnh viện. Thông tin thu thập được khi tiếp xúc lần đầu với bệnh nhân có thể chỉ ra nhu cầu cần thêm dữ liệu hoặc đánh giá chuyên sâu hơn. Ít nhất, nhu cầu đánh giá thêm được xác định bởi dịch vụ chăm sóc, điều trị và các dịch vụ được tìm kiếm và tình trạng hiện tại của bệnh nhân. Đánh giá bệnh nhân là phù hợp khi xem xét tình trạng, độ tuổi, nhu cầu sức khỏe và yêu cầu hoặc sở thích của bệnh nhân. Các quy trình này được thực hiện hiệu quả nhất khi các bác sĩ chăm sóc sức khỏe khác nhau chịu trách nhiệm về bệnh nhân làm việc cùng nhau. Tiêu chuẩn Sau đây là danh sách tất cả các tiêu chuẩn cho chức năng này. Chúng được trình bày ở đây để thuận tiện cho bạn mà không có các tuyên bố ý định hoặc các yếu tố có thể đo lường. Để biết thêm thông tin về các tiêu chuẩn này, vui lòng xem phần tiếp theo trong chương này, Tiêu chuẩn, Ý định và Các yếu tố có thể đo lường. Đánh giá bệnh nhân AOP.01.00 Tất cả bệnh nhân đều có nhu cầu chăm sóc sức khỏe được xác định thông qua quy trình đánh giá đã được bệnh viện xác định. AOP.01.01 Đánh giá ban đầu của mỗi bệnh nhân bao gồm tiền sử sức khỏe và đánh giá nhu cầu về thể chất, tâm lý, tinh thần/văn hóa, xã hội và kinh tế của bệnh nhân. AOP.01.02 Bệnh viện có quy trình chấp nhận đánh giá ban đầu từ các nguồn bên ngoài. AOP.01.03 Bệnh nhân được sàng lọc về dinh dưỡng, chức năng và các nhu cầu đặc biệt khác và được đánh giá thêm khi được chỉ định bởi quá trình sàng lọc. Đánh giá bệnh nhân (AOP) AOP.01.04 Tất cả bệnh nhân đều được sàng lọc cơn đau và đánh giá khi cơn đau xuất hiện. AOP.01.05 Tất cả bệnh nhân đều được đánh giá lại theo định kỳ dựa trên tình trạng và phương pháp điều trị của họ. Bệnh nhân ngã AOP.02.00 Bệnh viện xây dựng và triển khai quy trình nhằm giảm nguy cơ té ngã và tổn hại cho bệnh nhân do té ngã. Dịch vụ phòng thí nghiệm AOP.03.00 Các dịch vụ xét nghiệm có sẵn để đáp ứng nhu cầu của bệnh nhân và tất cả các dịch vụ xét nghiệm đều đáp ứng các tiêu chuẩn, luật pháp và quy định hiện hành của địa phương và quốc gia. AOP.03.01 Một hoặc nhiều cá nhân có trình độ chịu trách nhiệm quản lý dịch vụ xét nghiệm lâm sàng hoặc dịch vụ bệnh lý, và tất cả nhân viên phòng xét nghiệm đều có trình độ để thực hiện các xét nghiệm và giải thích kết quả. AOP.03.02 Bệnh viện đã xác định các yêu cầu về giám sát và quản lý chương trình xét nghiệm tại chỗ. AOP.03.03 Kết quả xét nghiệm được báo cáo trong khung thời gian quy định của chính sách bệnh viện. AOP.03.04 Tất cả các thiết bị thử nghiệm trong phòng thí nghiệm đều được kiểm tra, bảo trì và hiệu chuẩn thường xuyên, đồng thời lưu giữ hồ sơ phù hợp cho các hoạt động này. AOP.03.05 Thuốc thử và vật tư thiết yếu đều có sẵn và tất cả thuốc thử đều được đánh giá để đảm bảo độ chính xác và độ tin cậy của kết quả. AOP.03.06 Các thủ tục thu thập, xác định, xử lý, vận chuyển và thải bỏ mẫu vật một cách an toàn được thiết lập và thực hiện. AOP.03.07 Các chuẩn mực và phạm vi đã thiết lập được sử dụng để giải thích và báo cáo kết quả xét nghiệm lâm sàng. AOP.03.08 Bệnh viện đã triển khai các quy trình kiểm soát chất lượng và thử nghiệm năng lực dịch vụ xét nghiệm. AOP.03.09 Bệnh viện đảm bảo chất lượng dịch vụ do các phòng xét nghiệm theo hợp đồng cung cấp. Ngân hàng máu và/hoặc dịch vụ truyền máu AOP.04.00 Một hoặc nhiều cá nhân đủ tiêu chuẩn chịu trách nhiệm về ngân hàng máu và/hoặc các dịch vụ truyền máu và đảm bảo rằng các dịch vụ tuân thủ luật pháp và quy định cũng như các tiêu chuẩn thực hành được công nhận. AOP.04.01 Các hướng dẫn và quy trình lâm sàng được thực hiện để xử lý và quản lý máu và các sản phẩm máu. Dịch vụ X quang và Chẩn đoán hình ảnh AOP.05.00 Các dịch vụ chụp X-quang và chẩn đoán hình ảnh có sẵn để đáp ứng nhu cầu của bệnh nhân và tất cả các dịch vụ đều đáp ứng các tiêu chuẩn, luật và quy định hiện hành của địa phương và quốc gia. AOP.05.01 Một hoặc nhiều cá nhân có trình độ chịu trách nhiệm quản lý các dịch vụ chẩn đoán hình ảnh và X quang, và những cá nhân có trình độ và kinh nghiệm phù hợp sẽ thực hiện các nghiên cứu chẩn đoán hình ảnh, giải thích kết quả và báo cáo kết quả. AOP.05.02 Một chương trình an toàn về bức xạ và/hoặc chẩn đoán hình ảnh dành cho bệnh nhân, nhân viên và khách thăm được triển khai và tuân thủ các tiêu chuẩn, luật và quy định chuyên môn hiện hành. AOP.05.03 Kết quả nghiên cứu chẩn đoán hình ảnh và X quang có sẵn kịp thời theo quy định của chính sách bệnh viện. Đánh giá bệnh nhân (AOP) AOP.05.04 Tất cả các thiết bị được sử dụng để tiến hành các nghiên cứu chẩn đoán hình ảnh và X quang đều được kiểm tra, bảo trì và hiệu chuẩn thường xuyên, đồng thời lưu giữ hồ sơ phù hợp cho các hoạt động này. AOP.05.05 Bệnh viện đã triển khai các quy trình kiểm soát chất lượng dịch vụ chẩn đoán hình ảnh và X quang. AOP.05.06 Bệnh viện đảm bảo chất lượng dịch vụ do tất cả các nguồn dịch vụ chẩn đoán hình ảnh và X quang bên ngoài ký hợp đồng cung cấp. Dịch vụ Y học hạt nhân AOP.06.00 Khi áp dụng, bệnh viện thiết lập và thực hiện chương trình an toàn y học hạt nhân tuân thủ các tiêu chuẩn, luật và quy định chuyên môn hiện hành. Đánh giá bệnh nhân","b":[]}],"sec":"Vận chuyển"},{"c":"AOP.01.00","ch":"AOP","t":"Tất cả bệnh nhân đều có nhu cầu chăm sóc sức khỏe được xác định thông qua quy trình đánh giá đã được bệnh viện xác định.","p":"Quá trình đánh giá hiệu quả thúc đẩy các quyết định về nhu cầu chăm sóc, điều trị và dịch vụ của bệnh nhân. Vì các quyết\nđịnh được đưa ra dựa trên các đánh giá, nên quá trình đánh giá là năng động và liên tục trong suốt quá trình chăm sóc bệnh\nnhân.\n\nĐánh giá bệnh nhân xác định nhu cầu chăm sóc, ngay cả khi tình trạng của bệnh nhân thay đổi. Đánh giá bệnh nhân bao\ngồm ba quy trình chính:\n• Thu thập thông tin và dữ liệu về tiền sử sức khỏe của bệnh nhân và nhu cầu về thể chất, tâm lý và xã hội của họ\n• Phân tích dữ liệu đánh giá, bao gồm bất kỳ xét nghiệm chẩn đoán nào, để xác định nhu cầu chăm sóc sức khỏe của\nbệnh nhân.\n• Sử dụng thông tin để phát triển một kế hoạch chăm sóc cụ thể cho nhu cầu của bệnh nhân\n\nKhi bệnh nhân được nhập viện hoặc đăng ký chăm sóc, cho dù là chăm sóc/điều trị nội trú hay ngoại trú, cần phải thực\nhiện đánh giá đầy đủ liên quan đến lý do chăm sóc. Thông tin cần thiết phụ thuộc vào nhu cầu của bệnh nhân và bối cảnh\ncung cấp dịch vụ chăm sóc (ví dụ: chăm sóc nội trú hay ngoại trú). Chính sách của bệnh viện xác định nội dung đánh giá tối\nthiểu mà nhân viên lâm sàng phải đưa vào đánh giá của họ và trong mọi bối cảnh chăm sóc. Bệnh viện xác định bất kỳ dữ\nliệu đánh giá cụ thể nào phải được đưa vào bởi nhiều nhân viên lâm sàng.\n\nĐánh giá được thực hiện bởi từng chuyên khoa trong phạm vi thực hành, cấp phép, luật và quy định hiện hành hoặc chứng\nnhận của chuyên khoa đó. Chỉ những cá nhân đủ điều kiện mới được tiến hành đánh giá.\n\nTất cả nội dung từ các đánh giá phải có sẵn khi bắt đầu điều trị.","m":[{"t":"Chính sách của bệnh viện xác định, bằng văn bản, nội dung tối thiểu của các đánh giá đối với bệnh nhân nội trú cho mỗi chuyên khoa lâm sàng thực hiện đánh giá. (Xem thêm AOP.01.01, ME 2)","b":[]},{"t":"Chính sách của bệnh viện xác định, bằng văn bản, nội dung tối thiểu của các đánh giá đối với bệnh nhân ngoại trú cho mỗi chuyên khoa lâm sàng thực hiện đánh giá. (Xem thêm AOP.01.01, ME 2)","b":[]},{"t":"Chỉ những cá nhân đủ điều kiện được cấp phép, luật và quy định hiện hành hoặc chứng nhận mới được phép thực hiện đánh giá. (Xem thêm AOP.01.01, ME 3)","b":[]},{"t":"Bệnh viện xác định thông tin cần ghi lại để đánh giá.","b":[]}],"sec":"Đánh giá bệnh nhân"},{"c":"AOP.01.01","ch":"AOP","t":"Đánh giá ban đầu của mỗi bệnh nhân bao gồm tiền sử sức khỏe và đánh giá nhu cầu về thể chất, tâm lý, tinh thần/văn hóa, xã hội và kinh tế của bệnh nhân.","p":"Đánh giá ban đầu cho bệnh nhân rất quan trọng để xác định nhu cầu của bệnh nhân và lập kế hoạch chăm sóc\nbệnh nhân.\n\nĐánh giá đầy đủ được thực hiện liên quan đến khiếu nại chính tại thời điểm nhập viện hoặc đăng ký. Chính sách\ncủa bệnh viện xác định thông tin nào cần thiết tại thời điểm nhập viện hoặc đăng ký, ai chịu trách nhiệm thu\nthập và ghi lại thông tin này và cách ghi lại thông tin này.\n\nĐánh giá ban đầu cung cấp thông tin để thực hiện các việc sau:\n• Hiểu được dịch vụ chăm sóc mà bệnh nhân đang tìm kiếm.\n• Chọn cơ sở chăm sóc tốt nhất cho bệnh nhân.\n• Hình thành chẩn đoán ban đầu.\n• Hiểu được phản ứng của bệnh nhân đối với bất kỳ dịch vụ chăm sóc trước đó nào.\nChính sách của bệnh viện nêu rõ những đánh giá và tiền sử nào là bắt buộc trong quá trình đánh giá ban đầu. Các\nyếu tố chung của đánh giá ban đầu bao gồm:\n• Đánh giá thể chất\n• Tiền sử sức khỏe\n• Tiền sử dùng thuốc và dị ứng\n• Đánh giá tâm lý\n• Đánh giá xã hội và kinh tế\n• Đánh giá văn hóa và tinh thần\n\nĐánh giá tâm lý xác định nhận thức, quá trình suy nghĩ và trạng thái cảm xúc của bệnh nhân. Đánh giá xã hội và\nkinh tế không nhằm mục đích \"phân loại\" bệnh nhân; nó được sử dụng để xác định các rào cản có thể xảy ra\nkhi tiếp cận và thanh toán cho dịch vụ chăm sóc.\n\nCác yếu tố xã hội, văn hóa, tinh thần, gia đình và kinh tế của bệnh nhân có thể ảnh hưởng đến phản ứng của họ\nđối với bệnh tật và việc điều trị. Gia đình có thể rất hữu ích trong các lĩnh vực đánh giá này và trong việc hiểu\nmong muốn và sở thích của bệnh nhân.\n\nChính sách của bệnh viện cũng nêu rõ những điều sau:\n• Mỗi chuyên khoa có trách nhiệm hoàn thành những phần nào của đánh giá ban đầu\n• Nội dung tối thiểu cho đánh giá y khoa ban đầu\n• Nội dung tối thiểu cho đánh giá điều dưỡng ban đầu\n• Nội dung tối thiểu cho các đánh giá khác (ví dụ: vật lý trị liệu, liệu pháp ngôn ngữ)\n• Khung thời gian để hoàn thành đánh giá ban đầu\n• Các yêu cầu về tài liệu cho đánh giá ban đầu\n\nĐánh giá ban đầu cho bệnh nhân không cần phải do một người thực hiện. Chính sách của bệnh viện xác định chuyên khoa\nnào chịu trách nhiệm cho phần nào của đánh giá ban đầu. Chính sách của bệnh viện nêu rõ nội dung tối thiểu của đánh giá\ny khoa và điều dưỡng ban đầu và các đánh giá khác, khung thời gian hoàn thành đánh giá và yêu cầu về tài liệu đánh giá.\n\nĐánh giá ban đầu cho một số nhóm bệnh nhân yêu cầu phải sửa đổi quy trình đánh giá. Việc sửa đổi dựa trên các đặc điểm\nhoặc nhu cầu riêng biệt của từng nhóm bệnh nhân. Mỗi bệnh viện\nxác định những nhóm bệnh nhân đặc biệt đó và sửa đổi quy trình đánh giá để đáp ứng nhu cầu đặc biệt của họ. Đánh giá\nnhững bệnh nhân này đáp ứng nhu cầu và tình trạng của họ theo cách được chấp nhận về mặt văn hóa và bảo mật. Đánh\ngiá nhóm bệnh nhân đặc biệt được sửa đổi để phù hợp với luật pháp và quy định của địa phương cũng như các tiêu chuẩn\nchuyên môn.\n\nĐánh giá hoàn tất, dành cho những người chăm sóc bệnh nhân và đưa ra chẩn đoán ban đầu cũng như hiểu biết về nhu cầu\ny khoa và điều dưỡng của bệnh nhân để có thể bắt đầu chăm sóc và điều trị.\n\nTrong trường hợp khẩn cấp, đánh giá y khoa và điều dưỡng ban đầu có thể giới hạn ở nhu cầu và tình trạng rõ ràng của\nbệnh nhân. Trong trường hợp bệnh nhân cấp cứu cần phẫu thuật, một ghi chú ngắn và chẩn đoán trước phẫu thuật được\nghi lại trước khi phẫu thuật.\n\nBệnh viện phải xác định, bằng văn bản, các nhóm bệnh nhân đặc biệt mà bệnh viện phục vụ và yêu cầu một quy trình đánh\ngiá được sửa đổi. Ví dụ về các nhóm bệnh nhân đặc biệt bao gồm:\n•\nTrẻ sơ sinh, trẻ em và thanh thiếu niên\n•\nNgười già yếu\n•\nBệnh nhân giai đoạn cuối/sắp chết\n•\nBệnh nhân bị đau dữ dội hoặc mãn tính\n•\nPhụ nữ chuyển dạ hoặc đang phá thai\n•\nBệnh nhân mắc chứng rối loạn cảm xúc hoặc tâm thần\n•\nBệnh nhân nghi ngờ nghiện ma túy và/hoặc rượu\n•\nNạn nhân bị ngược đãi hoặc bỏ bê\n•\nBệnh nhân mắc bệnh truyền nhiễm hoặc truyền nhiễm\n•\nBệnh nhân có hệ thống miễn dịch bị suy yếu\n\nBệnh viện yêu cầu đánh giá ban đầu của bệnh nhân phải được hoàn thành và ghi lại trong vòng 24 giờ sau khi nhập viện.\nBệnh viện có thể xác định các tình huống cần đánh giá sớm hơn hoặc có thể chấp nhận đánh giá hạn chế. Những tình huống\nnày bao gồm những điều sau:\n•\nKhi tình trạng của bệnh nhân cho thấy, ví dụ, bệnh nhân không ổn định, bệnh nhân được lên lịch phẫu thuật trong vòng\nchưa đầy 24 giờ sau khi nhập viện hoặc khi việc chuyển viện sắp xảy ra\n•\nĐánh giá ngay lập tức các bệnh nhân cấp cứu hoặc các nhóm khác do bệnh viện xác định\n•\nKhi bệnh nhân cấp cứu được gửi đi phẫu thuật khẩn cấp","m":[{"t":"Tất cả bệnh nhân đều được đánh giá ban đầu phù hợp với các yêu cầu được xác định trong chính sách của bệnh viện.","b":[]},{"t":"Đánh giá bao gồm những nội dung sau:","b":["Khám sức khỏe","Tiền sử bệnh","Tiền sử dùng thuốc và dị ứng đã biết","Đánh giá tâm lý ban đầu theo tình trạng của bệnh nhân","Đánh giá kinh tế và xã hội ban đầu, khi cần thiết theo nhu cầu của bệnh nhân","Đánh giá tinh thần và văn hóa ban đầu, khi cần thiết theo nhu cầu của bệnh nhân (Xem thêm AOP.01.00, MEs 1 và 2)"]},{"t":"D Bệnh viện nêu rõ các yêu cầu về người chịu trách nhiệm đánh giá ban đầu và tính kịp thời của đánh giá, bao gồm những nội dung sau:","b":["Mỗi chuyên khoa chịu trách nhiệm hoàn thành những phần nào của đánh giá ban đầu","Nội dung tối thiểu cho đánh giá y khoa ban đầu","Nội dung tối thiểu cho đánh giá điều dưỡng ban đầu","Nội dung tối thiểu cho các đánh giá khác (ví dụ: vật lý trị liệu, trị liệu ngôn ngữ, dịch vụ xã hội)","Khung thời gian hoàn thành đánh giá ban đầu","Yêu cầu về tài liệu cho đánh giá ban đầu (Xem thêm AOP.01.00, ME 3)"]},{"t":"D Bệnh viện xác định, bằng văn bản, những nhóm bệnh nhân và quần thể mà nó phục vụ cần sửa đổi đánh giá ban đầu của họ.","b":[]},{"t":"Đánh giá ban đầu cho các quần thể bệnh nhân đặc biệt được sửa đổi để phản ánh nhu cầu của họ.","b":[]},{"t":"Đánh giá điều dưỡng ban đầu được hoàn thành trong vòng 8 giờ và đánh giá y tế được hoàn thành trong vòng 24 giờ sau khi nhập viện.","b":[]},{"t":"Đánh giá ban đầu dẫn đến chẩn đoán ban đầu hoặc các chẩn đoán cần điều trị và theo dõi.","b":[]},{"t":"Đánh giá điều dưỡng ban đầu dẫn đến danh sách các nhu cầu hoặc tình trạng điều dưỡng cụ thể cần chăm sóc điều dưỡng, can thiệp hoặc theo dõi.","b":[]},{"t":"Chẩn đoán trước phẫu thuật được ghi lại đối với những bệnh nhân cần phẫu thuật khẩn cấp. AOP chuẩn.01.02 Bệnh viện có quy trình chấp nhận đánh giá ban đầu từ các nguồn bên ngoài. Mục đích của AOP.01.02 Phải có quy trình chấp nhận đánh giá ban đầu từ các nguồn bên ngoài bao gồm xác thực thông tin có trong đánh giá vì cần có thông tin chính xác và cập nhật để cung cấp dịch vụ chăm sóc bệnh nhân an toàn. Đánh giá ban đầu có thể được thực hiện bởi một nguồn bên ngoài. Ví dụ về các nguồn bên ngoài bao gồm:","b":["Phòng khám của bác sĩ chăm sóc sức khỏe","Trung tâm chăm sóc ban đầu hoặc chăm sóc ngoại trú","Bác sĩ tư vấn hoặc giới thiệu Những lý do phổ biến để các nguồn bên ngoài đánh giá ban đầu bao gồm:","Giới thiệu đến một bác sĩ chuyên khoa do bệnh viện tuyển dụng","Nhập viện trực tiếp hoặc theo lịch trình","Giới thiệu để được phẫu thuật ngoại trú theo lịch trình hoặc phẫu thuật trong ngày Đánh giá ban đầu do một nguồn bên ngoài hoàn thành phải trong vòng 30 ngày trước đó. Khi đánh giá được hoàn thành một phần hoặc toàn bộ bởi một nguồn bên ngoài, thông tin trong đánh giá sẽ được một cá nhân đủ điều kiện xem xét và xác minh. Nếu có bất kỳ thay đổi nào đối với đánh giá, hồ sơ y tế sẽ được cập nhật và xác định bất kỳ xét nghiệm bổ sung nào có thể cần thiết liên quan đến thay đổi đó. Nếu đánh giá ban đầu đã hơn 30 ngày kể từ thời điểm nhập viện hoặc đăng ký, bệnh sử phải được cập nhật và khám sức khỏe lại. Đối với các đánh giá ban đầu được thực hiện và ghi lại trong vòng 30 ngày trở xuống trước khi nhập viện hoặc đăng ký, thông tin trong bệnh sử và đánh giá sẽ được xem xét và xác minh. Đánh giá này bao gồm những nội dung sau:","Bệnh sử và kết quả đánh giá của bệnh nhân","Kết quả xét nghiệm và các xét nghiệm chẩn đoán khác","Kế hoạch chăm sóc và điều trị được đề xuất Bất kỳ thay đổi nào về tình trạng của bệnh nhân kể từ khi đánh giá, hoặc \"không thay đổi\" nếu phù hợp, đều được ghi lại khi nhập viện. Các yếu tố có thể đo lường của AOP.01.02"]},{"t":"Đánh giá y tế ban đầu được chấp nhận có thời gian ít hơn hoặc bằng 30 ngày.","b":[]},{"t":"Đối với các đánh giá ban đầu có thời gian ít hơn hoặc bằng 30 ngày, đánh giá sẽ được xem xét và xác nhận; bất kỳ thay đổi nào về tình trạng của bệnh nhân kể từ khi đánh giá hoặc \"không thay đổi\" đều được ghi lại trong hồ sơ y tế của bệnh nhân tại thời điểm nhập viện hoặc đăng ký.","b":[]},{"t":"Nếu đánh giá ban đầu có thời gian lớn hơn 30 ngày tại thời điểm nhập viện hoặc đăng ký, bệnh sử sẽ được cập nhật và đánh giá ban đầu sẽ được lặp lại theo chính sách đánh giá ban đầu của bệnh viện.","b":[]}],"sec":"Đánh giá bệnh nhân"},{"c":"AOP.01.02","ch":"AOP","t":"Bệnh viện có quy trình chấp nhận đánh giá ban đầu từ các nguồn bên ngoài.","p":"","m":[],"sec":"Đánh giá bệnh nhân"},{"c":"AOP.01.03","ch":"AOP","t":"Bệnh nhân được sàng lọc về dinh dưỡng, chức năng và các nhu cầu đặc biệt khác và được đánh giá thêm khi được chỉ định bởi quá trình sàng lọc.","p":"Các cuộc sàng lọc ban đầu về nhu cầu dinh dưỡng, chức năng và các nhu cầu đặc biệt khác xác định những bệnh nhân có thể\ncần can thiệp bổ sung để chăm sóc an toàn, chất lượng cao.\n\nCác cuộc sàng lọc này có thể được tiến hành tại buổi đánh giá y tế hoặc điều dưỡng ban đầu. Bệnh viện sử dụng một công cụ\nsàng lọc để sàng lọc bệnh nhân về nhu cầu dinh dưỡng, chức năng và các nhu cầu đặc biệt khác. Thông tin thu thập được thông\nqua quá trình sàng lọc sẽ xác định xem bệnh nhân có cần đánh giá thêm hay không.\n\nQuy trình sàng lọc rất đơn giản và ở cấp độ cao, xác định xem có rủi ro hoặc vấn đề nào không. Nếu quá trình sàng lọc xác định\nđược rủi ro hoặc vấn đề, thì quá trình đánh giá sẽ được hoàn tất. Bệnh viện chuyển bệnh nhân\nđể đánh giá thêm, tại bệnh viện hoặc thông qua cộng đồng, để giải quyết các rủi ro hoặc vấn đề được xác định qua quá trình\nsàng lọc.\nCác công cụ sàng lọc được triển khai nhất quán trong toàn bệnh viện và được nhân viên lâm sàng được đào tạo sử dụng. Các\ncông cụ sàng lọc được phát triển bởi những cá nhân có trình độ có khả năng đánh giá thêm bất kỳ rủi ro nào đã xác định. Nhiều\nnhân viên lâm sàng có thể được đào tạo về cách sử dụng các công cụ và hoàn thành quá trình sàng lọc với bệnh nhân. Khi được\nchỉ định bởi quá trình sàng lọc, những cá nhân đủ trình độ sẽ hoàn thành quá trình đánh giá và xác định các biện pháp can thiệp\nhoặc một kế hoạch để giải quyết nhu cầu của bệnh nhân. Các ví dụ bao gồm:\n•\nRủi ro dinh dưỡng\no Một công cụ sàng lọc dựa trên bằng chứng về rủi ro dinh dưỡng có thể được phát triển bởi các y tá của bệnh\nviện.\no Các y tá, bác sĩ và chuyên gia dinh dưỡng được đào tạo để sử dụng các công cụ.\n\nĐánh giá bệnh\nnhân (AOP)\n\no\nSau đó, các chuyên gia dinh dưỡng sẽ tiến hành đánh giá dinh dưỡng và đưa ra biện pháp can thiệp\nchế độ ăn uống được khuyến nghị.\no\nCác chuyên gia dinh dưỡng tích hợp nhu cầu dinh dưỡng được xác định bằng đánh giá với các nhu cầu\nkhác của bệnh nhân.\n• Trạng thái chức năng\no  Một công cụ sàng lọc chức năng dựa trên bằng chứng, bao gồm khả năng thể chất, thị lực và\nthính giác, có thể được phát triển bởi các nhà trị liệu nghề nghiệp của bệnh viện.\no  Y tá và chuyên gia trị liệu nghề nghiệp, vật lý và ngôn ngữ được đào tạo sử dụng công cụ sàng lọc.\no  Các nhà trị liệu nghề nghiệp, vật lý và ngôn ngữ hoàn thành đánh giá chức năng.\no  Bác sĩ vật lý trị liệu và phục hồi chức năng sẽ yêu cầu liệu pháp chức năng để giải quyết các nhu\ncầu được xác định trong quá trình đánh giá.\n\nCác nhu cầu chuyên biệt khác có thể được xác định thông qua việc chăm sóc thường quy; ví dụ, nhân viên\nlâm sàng có thể quan sát thấy bệnh nhân gặp khó khăn khi nhìn hoặc nghe và giới thiệu bệnh nhân đi đánh\ngiá cần thiết.\n\nĐánh giá được hoàn thành bằng các công cụ dựa trên bằng chứng và được nhân viên lâm sàng được đào\ntạo sử dụng để xác định mức độ rủi ro hoặc mức độ nghiêm trọng của vấn đề và phát triển các biện pháp\ncan thiệp cụ thể để giải quyết rủi ro hoặc vấn đề.\n\nMột công cụ sàng lọc được sử dụng để đánh giá sự hiện diện của rủi ro hoặc vấn đề và thường đưa ra câu\ntrả lời là \"có hoặc không\".\n\nCác công cụ sàng lọc có thể được phát triển bởi một cá nhân đủ điều kiện để sàng lọc rủi ro hoặc vấn đề.\nViệc tạo một bảng câu hỏi ngắn cho bệnh nhân là một công cụ sàng lọc hữu ích, như trong các ví dụ sau:\n•\nHỏi bệnh nhân \"Bạn có giảm hoặc tăng hơn 2 kg trong 30 ngày qua không?\" để sàng lọc rủi ro dinh\ndưỡng\n•\nHỏi bệnh nhân \"Bạn có thể hoàn thành các nhiệm vụ vệ sinh hàng ngày mà không gặp khó khăn hoặc\ncần trợ giúp không?\" để sàng lọc rủi ro chức năng\n•\nYêu cầu bệnh nhân hoàn thành bài kiểm tra thì thầm ngắn để sàng lọc khiếm khuyết thính lực\n\nCác công cụ đánh giá được sử dụng để hoàn thành đánh giá chuyên sâu về rủi ro hoặc vấn đề của bệnh nhân\nvà được sử dụng để phát triển các biện pháp can thiệp cụ thể nhằm giải quyết rủi ro hoặc vấn đề.\n\nCác công cụ đánh giá đáp ứng các tiêu chí sau:\n•\nPhù hợp với rủi ro hoặc vấn đề đang được đánh giá.\n•\nPhù hợp với nhóm bệnh nhân đang được đánh giá (ví dụ: trẻ em, người lớn, người già).\n•\nDựa trên bằng chứng và được xác thực trong nhóm bệnh nhân đang được đánh giá.","m":[{"t":"Các công cụ sàng lọc dựa trên bằng chứng được sử dụng để xác định những bệnh nhân cần đánh giá dinh dưỡng thêm và các công cụ này được triển khai nhất quán trong toàn bệnh viện.","b":[]},{"t":"Bệnh nhân có kết quả sàng lọc cho thấy có nguy cơ hoặc vấn đề dinh dưỡng sẽ được đánh giá dinh dưỡng.","b":[]},{"t":"Các công cụ sàng lọc được sử dụng để xác định những bệnh nhân cần đánh giá chức năng thêm và các công cụ này được triển khai nhất quán trong toàn bệnh viện.","b":[]},{"t":"Bệnh nhân có kết quả sàng lọc cho thấy có nguy cơ hoặc vấn đề về chức năng sẽ được đánh giá chức năng.","b":[]},{"t":"Khi xác định được nhu cầu đánh giá chuyên khoa bổ sung, bệnh nhân sẽ được chuyển đến trong bệnh viện hoặc ra ngoài bệnh viện.","b":[]}],"sec":"Đánh giá bệnh nhân"},{"c":"AOP.01.04","ch":"AOP","t":"Tất cả bệnh nhân đều được sàng lọc cơn đau và đánh giá khi cơn đau xuất hiện.","p":"Đau ảnh hưởng rất lớn đến chất lượng cuộc sống của bệnh nhân, ảnh hưởng đến quá trình chữa bệnh và có thể ảnh hưởng\nđến sức khỏe thể chất, tâm lý và xã hội.\n\nViệc sàng lọc xác định những người có nguy cơ hoặc có khả năng cần đánh giá chuyên sâu hơn. Việc sàng lọc có phạm vi hẹp,\ntrong khi phạm vi đánh giá toàn diện hơn. Đánh giá là một quá trình có hệ thống được thực hiện để đánh giá các nhu cầu sau\nđó có thể được đáp ứng hoặc lập kế hoạch xung quanh các nhu cầu đó về cách đáp ứng các nhu cầu đó, do đó, cá nhân tiến\nhành đánh giá phải có chuyên môn hoặc chuyên khoa trong lĩnh vực được đánh giá.\n\nCác công cụ sàng lọc có phạm vi hẹp hơn, hời hợt hơn và có lợi cho việc xác định những người có nguy cơ. Một công cụ sàng\nlọc được sử dụng để xác định những bệnh nhân bị đau. Quá trình sàng lọc rất đơn giản, ở cấp độ cao và xác định rằng có tồn\ntại rủi ro hoặc vấn đề liên quan đến cơn đau hay không. Nếu quá trình sàng lọc xác định được rủi ro hoặc vấn đề, thì quá trình\nđánh giá sẽ được hoàn tất. Quá trình sàng lọc cơn đau có thể bao gồm một hoặc nhiều câu hỏi đơn giản mà nhân viên lâm\nsàng được đào tạo có thể hỏi. Kết quả sàng lọc cơn đau được ghi lại trong hồ sơ y tế của bệnh nhân.\n\nThông tin thu thập được qua quá trình sàng lọc sẽ xác định xem bệnh nhân có cần đánh giá thêm hay không. Sau đó, đánh giá\nđược sử dụng để khớp nhu cầu của cá nhân với loại hình và mức độ chăm sóc, điều trị hoặc dịch vụ phù hợp.\n\nNếu việc chăm sóc, điều trị hoặc dịch vụ đã lên kế hoạch có thể gây đau, điều này cũng sẽ chỉ ra nhu cầu đánh giá cơn đau.\n\nĐánh giá cơn đau phù hợp với bệnh nhân, bao gồm những điều sau:\n•\nĐộ tuổi của bệnh nhân\n•\nTình trạng bệnh nhân (ví dụ: được an thần hoặc tỉnh táo)\n•\nBất kỳ rào cản nào (ví dụ: không có khả năng nói hoặc nghe hoặc chậm phát triển)\n\nĐánh giá cơn đau là đánh giá chuyên sâu hơn về cơn đau của bệnh nhân và được sử dụng để đưa ra các biện pháp can thiệp\ncụ thể nhằm giải quyết cơn đau. Đánh giá cơn đau được ghi lại trong hồ sơ y tế của bệnh nhân.\n\nCơn đau của bệnh nhân được giải quyết ngay lập tức và có thể bao gồm việc giới thiệu hoặc chuyển đến một cơ sở chăm sóc\nkhác. Ví dụ, một bệnh nhân ngoại trú bị đau dữ dội có thể được đưa vào viện như một bệnh nhân nội trú để đánh giá và điều\ntrị thêm cơn đau của họ, hoặc một bệnh nhân nội trú trong khoa y tế tổng quát có thể cần được chuyển đến khoa chăm sóc\nđặc biệt để theo dõi xem có cần gây tê ngoài màng cứng để điều trị cơn đau của họ hay không.\n\nMột công cụ sàng lọc được sử dụng để đánh giá sự hiện diện của rủi ro hoặc vấn đề và thường đưa ra câu trả lời là \"có hoặc\nkhông\". Các ví dụ về các câu hỏi có thể được sử dụng trong quá trình sàng lọc bao gồm:\n•\nBạn có bị đau ngay bây giờ không?\n•\nCơn đau có khiến bạn không ngủ được vào ban đêm không?\n•\nCơn đau có khiến bạn không thể tham gia các hoạt động không?\n•\nBạn có bị đau hàng ngày không?\n\nCác công cụ dựa trên bằng chứng được sử dụng để đo mức độ nghiêm trọng của cơn đau của bệnh nhân. Ví dụ về thang đo\nmức độ đau bao gồm:\n•\nThang đo khuôn mặt Wong-Baker\n•\nThang đo FLACC (Khuôn mặt, Chân, Hoạt động, Khóc, Dễ dỗ dành)\n•\nThang đo THOẢI MÁI\n•\nThang đo Đau theo Hành vi\n•\nThang đo Đau ở Trẻ sơ sinh\n\nĐánh giá cơn đau cũng đánh giá cường độ và chất lượng cơn đau, bao gồm:\n•\nTính chất cơn đau (ví dụ, sắc, âm ỉ hoặc nóng rát)\n•\nTần suất\n•\nVị trí\n•\nThời gian\n\n•Tiền sử đau (ví dụ, cơn đau bắt đầu khi nào, hoạt động nào gây ra cơn đau, bệnh nhân đã thử phương pháp điều\ntrị nào để giảm đau)\n• Điều gì làm cơn đau giảm bớt hoặc tệ hơn\n• Mục tiêu giảm đau của bệnh nhân là gì (ví dụ, không đau hay giảm đau đủ để hoàn thành hoặc\ntham gia vào các hoạt động cụ thể)\n\nĐánh giá cơn đau, bao gồm cả công cụ đánh giá nào được sử dụng, được ghi lại trong hồ sơ y tế của bệnh nhân\nđể cho phép nhóm chăm sóc dễ dàng xác định xu hướng trong các biện pháp can thiệp giảm đau và giảm đau của\nbệnh nhân.","m":[{"t":"Tất cả bệnh nhân nội trú đều được sàng lọc cơn đau và quá trình sàng lọc được ghi lại.","b":[]},{"t":"Bệnh nhân ngoại trú có tình trạng, chẩn đoán hoặc hoàn cảnh có thể chỉ ra rằng họ có nguy cơ bị đau sẽ được sàng lọc cơn đau.","b":[]},{"t":"Khi cơn đau được xác định bằng cách sàng lọc, đánh giá cơn đau sẽ được thực hiện và ghi lại. (Xem thêm COP.07.00, ME 1)","b":[]},{"t":"Bệnh nhân được đánh giá lại mức độ đau sau bất kỳ can thiệp kiểm soát cơn đau nào.","b":[]},{"t":"Nếu cần, bệnh nhân sẽ được chuyển đến cơ sở chăm sóc có đủ khả năng và nguồn lực để điều trị cơn đau cho bệnh nhân. AOP chuẩn.01.05 Tất cả bệnh nhân đều được đánh giá lại theo định kỳ dựa trên tình trạng và phương pháp điều trị của họ. Mục đích của AOP.01.05 Đánh giá lại là chìa khóa để hiểu cách bệnh nhân phản ứng với phương pháp điều trị và để hiểu liệu các quyết định chăm sóc có hiệu quả hay không. Bệnh nhân được đánh giá lại trong suốt quá trình chăm sóc theo các khoảng thời gian dựa trên tình trạng và phương pháp điều trị của họ theo quy định trong chính sách của bệnh viện. Kết quả của các lần đánh giá lại này được ghi lại trong hồ sơ y tế của bệnh nhân. Chính sách của bệnh viện xác định tần suất đánh giá lại của các thành viên khác nhau trong nhóm chăm sóc sức khỏe. Bác sĩ phải đánh giá bệnh nhân có nhu cầu chăm sóc cấp tính ít nhất hàng ngày, bao gồm cả cuối tuần và khi có thay đổi đáng kể về tình trạng của bệnh nhân. Chính sách của bệnh viện xác định tần suất bệnh nhân được y tá đánh giá lại. Điều này sẽ thay đổi rất nhiều tùy thuộc vào nhu cầu, tình trạng và phương pháp điều trị của bệnh nhân. Ví dụ, bệnh nhân mới đặt nội khí quản có thể cần được điều dưỡng đánh giá lại sau mỗi giờ, trong khi bệnh nhân mắc bệnh mãn tính ổn định với đường thở đã được thiết lập có thể cần được điều dưỡng đánh giá lại sau mỗi bốn giờ. Chính sách của bệnh viện xác định tần suất bệnh nhân được các thành viên khác trong nhóm chăm sóc đánh giá lại, bao gồm:","b":["Chuyên gia trị liệu hô hấp","Chuyên gia vật lý trị liệu, nghề nghiệp và ngôn ngữ trị liệu","Nhân viên xã hội hoặc các dịch vụ xã hội khác Đánh giá lại diễn ra theo chính sách của bệnh viện. Đánh giá lại được hoàn thành và kết quả được ghi lại trong hồ sơ y tế của bệnh nhân trong các trường hợp sau:","Theo các khoảng thời gian xác định bởi các thành viên khác nhau của nhóm chăm sóc, bao gồm bác sĩ, y tá và những người khác","Hàng ngày bởi bác sĩ đối với bệnh nhân chăm sóc cấp tính","Để ứng phó với sự thay đổi đáng kể về tình trạng của bệnh nhân","Nếu chẩn đoán của bệnh nhân thay đổi và nhu cầu chăm sóc cần phải lập kế hoạch lại","Để xác định xem thuốc và các phương pháp điều trị khác có thành công hay không và bệnh nhân có thể được chuyển viện hoặc xuất viện Một số bệnh nhân không cấp tính có thể không cần đánh giá bác sĩ hàng ngày (ví dụ, bệnh nhân tâm thần ổn định đang tham gia các buổi trị liệu nhóm hoặc bệnh nhân đã qua giai đoạn cấp tính của bệnh hoặc phẫu thuật và chỉ đang được điều trị phục hồi chức năng). Chính sách của bệnh viện xác định những bệnh nhân không cần đánh giá bác sĩ hàng ngày. Các yếu tố có thể đo lường của AOP.01.05"]},{"t":"Chính sách của bệnh viện xác định, bằng văn bản, tần suất bệnh nhân được các thành viên khác nhau của nhóm chăm sóc sức khỏe đánh giá lại và các trường hợp khác khi cần đánh giá lại, bao gồm các trường hợp sau:","b":["Các khoảng thời gian được xác định bởi các thành viên khác nhau của nhóm chăm sóc, bao gồm bác sĩ, y tá và các nhân viên lâm sàng khác (ví dụ: nhà trị liệu, nhân viên xã hội)","Khi có sự thay đổi đáng kể về tình trạng bệnh nhân","Khi chẩn đoán đã thay đổi và kế hoạch chăm sóc cần được sửa đổi (Xem thêm COP.01.01, ME 3)","Để xác định xem bệnh nhân đã sẵn sàng để chuyển viện hay xuất viện chưa"]},{"t":"Bác sĩ đánh giá lại bệnh nhân ít nhất hàng ngày, bao gồm cả cuối tuần, trong giai đoạn cấp tính của quá trình chăm sóc và điều trị của họ.","b":[]},{"t":"Chính sách của bệnh viện xác định, bằng văn bản, các nhóm bệnh nhân có thể không cần đánh giá hàng ngày và xác định khoảng thời gian đánh giá lại tối thiểu cho những bệnh nhân này.","b":[]},{"t":"Đánh giá lại được ghi lại trong hồ sơ y tế của bệnh nhân. Bệnh nhân ngã","b":[]}],"sec":"Đánh giá bệnh"},{"c":"AOP.01.05","ch":"AOP","t":"Tất cả bệnh nhân đều được đánh giá lại theo định kỳ dựa trên tình trạng và phương pháp điều trị của họ.","p":"","m":[],"sec":"Đánh giá bệnh"},{"c":"AOP.02.00","ch":"AOP","t":"Bệnh viện xây dựng và triển khai quy trình nhằm giảm nguy cơ té ngã và tổn hại cho bệnh nhân do té ngã.","p":"Nhiều chấn thương trong bệnh viện đối với cả bệnh nhân nội trú và ngoại trú là do ngã, do đó cần có chương trình\nphòng ngừa té ngã toàn diện để ngăn ngừa chấn thương cho bệnh nhân.\n\nNguy cơ té ngã liên quan đến bệnh nhân, tình huống và/hoặc vị trí. Các rủi ro liên quan đến bệnh nhân bao gồm\nnhưng không giới hạn ở những điều sau:\n• Tuổi\n• Tiền sử bệnh\n• Tiền sử té ngã của bệnh nhân\n• Sử dụng thuốc\n• Sử dụng chất gây nghiện\n• Các bệnh đi kèm khác\n• Rối loạn dáng đi hoặc thăng bằng\n• Suy giảm thị lực\n• Thay đổi trạng thái tinh thần\n• Các mối nguy hiểm về môi trường (ví dụ: sàn trơn trượt, ánh sáng kém, phòng bừa bộn)\n\nBệnh nhân té ngã là mối lo ngại đáng kể về an toàn và có thể dẫn đến các chấn thương nghiêm trọng như gãy xương,\nchấn thương đầu, vết rách và tử vong.\n\nNhững bệnh nhân ban đầu được đánh giá là có nguy cơ té ngã thấp có thể có nguy cơ té ngã thay đổi trong thời gian\nnằm viện hoặc giữa các lần khám ngoại trú. Lý do thay đổi nguy cơ té ngã bao gồm những điều sau:\n• Phẫu thuật và/hoặc gây mê\n• Tình trạng bệnh nhân thay đổi đột ngột\n• Điều chỉnh thuốc\n\nNhiều bệnh nhân cần được đánh giá lại trong thời gian nằm viện do những thay đổi về tình trạng và nguy cơ té\nngã này. Các tiêu chí sàng lọc và đánh giá nguy cơ té ngã xác định những bệnh nhân được coi là có nguy cơ té ngã\ncao. Các cuộc sàng lọc, đánh giá và bất kỳ biện pháp can thiệp nào được áp dụng đều được ghi lại trong hồ sơ bệnh\nán của bệnh nhân.\nBệnh viện thiết lập chương trình giảm nguy cơ té ngã dựa trên các chính sách và/hoặc quy trình phù hợp. Nếu xảy\nra té ngã, bệnh viện sẽ đánh giá tình trạng té ngã, thực hiện hành động để giảm nguy cơ té ngã trong tương lai và\ngiảm nguy cơthương tích. Chương trình giảm nguy cơ té ngã bao gồm đánh giá rủi ro và đánh giá lại định kỳ đối\nvới một nhóm bệnh nhân cụ thể và/hoặc môi trường cung cấp dịch vụ chăm sóc (chẳng hạn như những dịch vụ\nđược thực hiện trong các chuyến tham quan an toàn định kỳ). Các biện pháp và biện pháp can thiệp được thực\nhiện để giảm nguy cơ té ngã cho bệnh nhân, tình huốngvà địa điểm được đánh giá là có nguy cơ.\nCác tình huống cụ thể có thể gây ra nguy cơ té ngã. Ví dụ, một bệnh nhân đến khoa ngoại trú từ một cơ sở chăm\nsóc dài hạn bằng xe cứu thương để chụp X-quang có thể có nguy cơ bị ngã trong tình huống đó khi chuyển từ xe\ncứu thương sang bàn khám hoặc khi thay đổi tư thế khi nằm trên bàn khám hẹp.\nCác địa điểm cụ thể có thể có nguy cơ té ngã cao hơn do các dịch vụ được cung cấp. Ví dụ, khoa vật lý trị liệu (nội\ntrú hoặc ngoại trú) có nhiều loại thiết bị chuyên dụng mà bệnh nhân sử dụng có thể làm tăng nguy cơ té ngã, chẳng\nhạn như thanh song song, cầu thang độc lập và thiết bị tập thể dục. Khi các địa điểm cụ thể được xác định là khu\nvực có nguy cơ té ngã cao hơn, bệnh viện có thể xác định rằng tất cả bệnh nhân đến các địa điểm đó đều được coi\nlà có nguy cơ té ngã và thực hiện các biện pháp chung để giảm thiểu nguy cơ té ngã áp dụng cho tất cả bệnh nhân.\nTất cả bệnh nhân nội trú đều được đánh giá nguy cơ té ngã bằng các công cụ đánh giá dựa trên bằng chứng\nvà/hoặc các phương pháp phù hợp với nhóm bệnh nhân của bệnh viện. Ví dụ, bệnh nhân nhi cần có công cụ đánh\ngiá nguy cơ té ngã ở trẻ em, chẳng hạn như Điểm Humpty Dumpty hoặc công cụ GRAF-PIF. Các đơn vị chuyên\nkhoa có thể thích các công cụ hướng đến nhóm dân số cụ thể của họ (ví dụ: Hệ thống đánh giá rủi ro té ngã sản\nkhoa dành cho phụ nữ trong khoa sản hoặc Công cụ đánh giá rủi ro té ngã tâm thần Edmonson (EPFRAT) dành\ncho bệnh nhân tâm thần.\nCác nhà lãnh đạo bệnh viện tiến hành đánh giá rủi ro để xác định các dịch vụ và nhóm bệnh nhân có nguy cơ cao\nnhằm sàng lọc rủi ro té ngã tại các khoa ngoại trú. Tuy nhiên, bệnh viện có thể chọn sàng lọc tất cả bệnh nhân\nngoại trú hoặc những bệnh nhân trong các khoa có nguy cơ té ngã cao hơn, dựa trên tình trạng, chẩn đoán, tình\nhuống và/hoặc vị trí. Các ví dụ có thể bao gồm:\n• Tất cả bệnh nhân trong khoa vật lý trị liệu ngoại trú\n• Tất cả bệnh nhân đến từ các cơ sở chăm sóc dài hạn bằng xe cứu thương để thực hiện các thủ thuật ngoại trú\n• Bệnh nhân được lên lịch phẫu thuật ngoại trú liên quan đến gây mê hoặc an thần\n• Bệnh nhân bị rối loạn dáng đi hoặc thăng bằng hoặc sử dụng thiết bị hỗ trợ đi lại\n• Bệnh nhân khiếm thị\n• Bệnh nhi dưới 2 tuổi\nNếu nguy cơ té ngã được chỉ ra từ quá trình sàng lọc, các biện pháp can thiệp dựa trên bằng chứng sẽ được triển\nkhai để giảm nguy cơ té ngã cho những bệnh nhân đó.\nViệc sàng lọc thường bao gồm việc thực hiện đánh giá đơn giản đối với bệnh nhân để xác định xem họ có nguy cơ\nté ngã hay không. Các công cụ sàng lọc thường được sử dụng và bao gồm các câu hỏi hoặc mục được sử dụng để\nxác định bệnh nhân có nguy cơ té ngã. Ví dụ, các câu hỏi có thể yêu cầu trả lời có/không đơn giản hoặc công cụ có\nthể bao gồm việc chỉ định điểm cho từng mục dựa trên phản hồi của bệnh nhân. Bệnh viện có thể xác định cách\nthức diễn ra quá trình sàng lọc. Ví dụ, sàng lọc có thể được thực hiện bởi nhân viên đăng ký hoặc bệnh nhân có thể\nđược phép tự sàng lọc, chẳng hạn như tại ki-ốt khi vào khoa ngoại trú. Ví dụ về các câu hỏi sàng lọc đơn giản có\nthể bao gồm \"Bạn có cảm thấy không vững khi đứng hoặc đi bộ không?\"; \"Bạn có lo lắng về việc té ngã không?\"; và\n\"Bạn có bị té ngã trong năm qua không?\"","m":[{"t":"Bệnh viện sàng lọc tất cả bệnh nhân nội trú để phát hiện nguy cơ té ngã và sử dụng các công cụ sàng lọc dựa trên bằng chứng phù hợp với nhóm bệnh nhân.","b":[]},{"t":"Bệnh viện sàng lọc tất cả bệnh nhân ngoại trú có tình trạng, chẩn đoán, hoàn cảnh hoặc vị trí có thể khiến họ có nguy cơ bị ngã và sử dụng các công cụ sàng lọc phù hợp với bệnh nhân được phục vụ.","b":[]},{"t":"Bệnh viện thực hiện quy trình đánh giá và, khi cần thiết, đánh giá lại những bệnh nhân có nguy cơ té ngã do tình trạng thay đổi hoặc đã có nguy cơ té ngã dựa trên đánh giá có ghi chép.","b":[]},{"t":"Các biện pháp can thiệp nhằm giảm nguy cơ té ngã được thực hiện cho những bệnh nhân, tình huống và địa điểm được xác định trong bệnh viện được đánh giá là có nguy cơ và các biện pháp can thiệp được ghi lại. Dịch vụ phòng thí nghiệm Lưu ý: Các phòng xét nghiệm được yêu cầu phải có sự công nhận cụ thể theo luật pháp và quy định của địa phương (ví dụ: ISO 15189) có thể trình bày xác minh về sự công nhận này như bằng chứng tuân thủ các yêu cầu có liên quan cho các giám định viên trong quá trình khảo sát công nhận bệnh viện JCI. Bằng chứng tuân thủ phải bao gồm tất cả các chuyên khoa và chuyên khoa phụ do phòng xét nghiệm bệnh viện cung cấp. Khảo sát JCI bao gồm các chuyên khoa và chuyên khoa phụ của phòng xét nghiệm (ví dụ: ngân hàng máu) không nằm trong phạm vi công nhận phòng xét nghiệm hiện có.","b":[]}],"sec":"Bệnh nhân ngã"},{"c":"AOP.03.00","ch":"AOP","t":"Các dịch vụ xét nghiệm có sẵn để đáp ứng nhu cầu của bệnh nhân và tất cả các dịch vụ xét nghiệm đều đáp ứng các tiêu chuẩn, luật pháp và quy định hiện hành của địa phương và quốc gia.","p":"Dịch vụ xét nghiệm là thiết yếu đối với quá trình chẩn đoán và điều trị và do đó phải đáp ứng các yêu cầu để đảm\nbảo chất lượng dữ liệu từ các xét nghiệm trong phòng xét nghiệm.\n\nBệnh viện có hệ thống cung cấp dịch vụ xét nghiệm dựa trên nhu cầu của bệnh nhân.\n\nCác dịch vụ xét nghiệm được tổ chức và cung cấp theo cách đáp ứng các tiêu chuẩn, luật và quy định hiện hành\ncủa địa phương và quốc gia. Dịch vụ xét nghiệm có sẵn sau giờ làm việc bình thường cho các trường hợp khẩn\ncấp.\n\nDịch vụ xét nghiệm có thể được cung cấp trong bệnh viện, theo thỏa thuận với một tổ chức khác (ví dụ: phòng\nxét nghiệm theo hợp đồng) hoặc cả hai. Bệnh viện xác định và liên hệ với các chuyên gia trong các lĩnh vực chẩn\nđoán chuyên khoa, chẳng hạn như ký sinh trùng học, virus học hoặc độc chất học, khi cần.\n\nCác nguồn bên ngoài thuận tiện cho bệnh nhân tiếp cận. Bệnh viện lựa chọn các nguồn bên ngoài dựa trên\nkhuyến nghị của người đứng đầu phòng xét nghiệm hoặc cá nhân khác chịu trách nhiệm về các dịch vụ xét\nnghiệm. Các nguồn dịch vụ xét nghiệm bên ngoài đáp ứng các luật và quy định hiện hành và có hồ sơ chấp nhận\nđược về các dịch vụ chính xác, kịp thời. Bệnh nhân được thông báo khi một nguồn dịch vụ xét nghiệm bên ngoài\nthuộc sở hữu của bác sĩ giới thiệu.","m":[{"t":"Các dịch vụ xét nghiệm, bao gồm các nguồn dịch vụ xét nghiệm bên ngoài, đáp ứng các tiêu chuẩn, luật và quy định hiện hành của địa phương và quốc gia.","b":[]},{"t":"Các dịch vụ xét nghiệm đáp ứng nhu cầu của bệnh nhân và các dịch vụ khác mà bệnh viện cung cấp, bao gồm quy trình tiếp cận các dịch vụ xét nghiệm sau giờ làm việc và cho các nhu cầu khẩn cấp.","b":[]},{"t":"Các chuyên gia trong các lĩnh vực chẩn đoán chuyên khoa được liên hệ khi cần. (Xem thêm GLD.05.00, ME 1)","b":[]}],"sec":"Dịch vụ phòng thí nghiệm"},{"c":"AOP.03.01","ch":"AOP","t":"Một hoặc nhiều cá nhân có trình độ chịu trách nhiệm quản lý dịch vụ xét nghiệm lâm sàng hoặc dịch vụ bệnh lý, và tất cả nhân viên phòng xét nghiệm đều có trình độ để thực hiện các xét nghiệm và giải thích kết quả.","p":"Dịch vụ xét nghiệm lâm sàng được quản lý bởi một cá nhân có trình độ để đảm bảo rằng phòng xét\nnghiệm và các dịch vụ của phòng xét nghiệm đáp ứng nhu cầu, luật pháp và quy định của bệnh nhân.\nNhân viên phòng xét nghiệm có trình độ thực hiện các xét nghiệm và giải thích kết quả để đảm bảo rằng\ndữ liệu thu thập được thông qua các dịch vụ xét nghiệm là chính xác.\n\nDịch vụ xét nghiệm lâm sàng được quản lý bởi một cá nhân có trình độ thông qua giáo dục, đào tạo, kinh\nnghiệm và các yêu cầu của luật pháp và quy định. Cá nhân này chịu trách nhiệm về cơ sở xét nghiệm, các\ndịch vụ được cung cấp trong phòng xét nghiệm và các xét nghiệm được thực hiện bên ngoài phòng xét\nnghiệm, bao gồm cả xét nghiệm tại chỗ.\n\nViệc giám sát các dịch vụ bên ngoài phòng xét nghiệm không bao gồm việc giám sát hàng ngày các hoạt\nđộng đó. Việc giám sát hàng ngày vẫn là trách nhiệm của các nhà lãnh đạo của khoa hoặc đơn vị nơi tiến\nhành xét nghiệm. Khi cá nhân này cung cấp tư vấn lâm sàng hoặc ý kiến y khoa, họ là bác sĩ, tốt nhất là\nbác sĩ bệnh học. Các dịch vụ xét nghiệm chuyên khoa và chuyên khoa phụ được quản lý bởi những cá\nnhân có trình độ phù hợp.\n\nNhân viên phòng xét nghiệm được định hướng vào công việc của họ và được giao nhiệm vụ phù hợp với\nđào tạo và kinh nghiệm của họ. Phòng xét nghiệm triển khai chương trình tuyển dụng cho phép nhân\nviên thực hiện các xét nghiệm nhanh chóng và đảm bảo nhân viên phòng xét nghiệm trong mọi giờ hoạt\nđộng và trong các trường hợp khẩn cấp.\n\nBệnh viện xác định một người đứng đầu phòng xét nghiệm đủ tiêu chuẩn để giám sát các dịch vụ xét\nnghiệm. Trách nhiệm giám sát bao gồm các dịch vụ được cung cấp trong và ngoài phòng xét nghiệm.\n\nViệc giám sát các dịch vụ bên ngoài phòng xét nghiệm bao gồm đảm bảo các chính sách và thông lệ nhất\nquán trên toàn bệnh viện, bao gồm:\n• Đào tạo\n• Quản lý vật tư\n• Kiểm tra và bảo dưỡng thiết bị\n• Giám sát chương trình xét nghiệm tại chỗ\n\nYêu cầu về nhân sự phòng xét nghiệm bao gồm:\n• Giáo dục, đào tạo, trình độ và kinh nghiệm của các thành viên nhân viên phòng xét nghiệm thực hiện và\ndiễn giải các xét nghiệm trong phòng xét nghiệm\n• Xác định nhân viên được chấp thuận thực hiện xét nghiệm tại chỗ\n• Xác định nhân viên chỉ đạo hoặc giám sát các nhân viên khác thực hiện xét nghiệm","m":[{"t":"Phòng xét nghiệm lâm sàng và các dịch vụ xét nghiệm khác trên toàn bệnh viện được chỉ đạo và giám sát bởi một hoặc nhiều cá nhân có trình độ. (Xem thêm GLD.06.00, ME 1)","b":[]},{"t":"Trách nhiệm của người đứng đầu phòng thí nghiệm có trình độ bao gồm những điều sau đây:","b":["Phát triển, thực hiện và duy trì các chính sách và thủ tục","Giám sát hành chính các dịch vụ phòng thí nghiệm","Duy trì bất kỳ chương trình kiểm soát chất lượng cần thiết nào","Phát triển và triển khai chương trình tuyển dụng","Đề xuất các nguồn dịch vụ phòng thí nghiệm bên ngoài","Giám sát và xem xét tất cả các dịch vụ phòng thí nghiệm"]},{"t":"Tất cả nhân viên phòng thí nghiệm đều có đủ trình độ để thực hiện và giải thích các xét nghiệm.","b":[]},{"t":"Một chương trình cung cấp nhân sự phòng thí nghiệm được triển khai để nhân viên có thể thực hiện xét nghiệm nhanh chóng và cung cấp nhân sự trong suốt giờ hoạt động và trong trường hợp khẩn cấp.","b":[]},{"t":"Đội ngũ giám sát phòng thí nghiệm được xác định và có đủ trình độ và kinh nghiệm phù hợp cho vai trò này.","b":[]}],"sec":"Dịch vụ phòng thí nghiệm"},{"c":"AOP.03.02","ch":"AOP","t":"Bệnh viện đã xác định các yêu cầu về giám sát và quản lý chương trình xét nghiệm tại chỗ.","p":"Bệnh viện phải có phương pháp tiếp cận được xác định rõ ràng và có cấu trúc tốt đối với xét nghiệm tại điểm chăm sóc để\nđảm bảo rằng xét nghiệm được thực hiện an toàn và đúng cách và kết quả thu được là chính xác và đáng tin cậy.\n\nXét nghiệm tại điểm chăm sóc (POCT) là xét nghiệm được thực hiện tại các địa điểm bên ngoài môi trường phòng xét\nnghiệm truyền thống, thường là tại hoặc gần nơi cung cấp dịch vụ chăm sóc cho bệnh nhân.\n\nCá nhân chịu trách nhiệm về dịch vụ xét nghiệm hoặc người được chỉ định đủ điều kiện khác chịu trách nhiệm giám sát và\nquản lý POCT.\n\nBệnh viện xây dựng chương trình POCT bao gồm các nội dung sau:\n• Lựa chọn xét nghiệm cần thực hiện\n• Xác định nhân viên thực hiện xét nghiệm\n• Thiết lập giao thức báo cáo kết quả xét nghiệm bất thường\n• Xác định quy trình báo cáo kết quả quan trọng\n• Xác định quy trình bao gồm đại diện của nhân viên lâm sàng trong việc xây dựng và đánh giá chương trình POCT\n\nNhân viên thực hiện POCT cần được đào tạo cho từng xét nghiệm được thực hiện. Nhân viên phải hoàn thành đánh giá\nnăng lực cho từng xét nghiệm để xác nhận rằng họ biết cách thực hiện xét nghiệm và đảm bảo kết quả chính xác. Nhân\nviên thực hiện POCT hiểu quy trình báo cáo kết quả bất thường và quan trọng.\n\nCác xét nghiệm kiểm soát chất lượng và tài liệu của chúng phải được thực hiện theo hướng dẫn của nhà sản xuất. Tất cả\nnhân viên thực hiện POCT đều tuân thủ các quy trình kiểm soát chất lượng và biết những hành động cần thực hiện nếu\nmẫu kiểm soát chất lượng nằm ngoài phạm vi xét nghiệm do nhà sản xuất chỉ định. Kết quả của các xét nghiệm kiểm soát\nchất lượng và bất kỳ hành động khắc phục nào đều được ghi lại.\n\nPOCT được theo dõi và đánh giá để đảm bảo rằng chương trình đáp ứng được nhu cầu của bệnh nhân và nhà cung cấp\ndịch vụ chăm sóc sức khỏe.\n\nCác xét nghiệm tại chỗ bao gồm các xét nghiệm được thực hiện và diễn giải tại hoặc gần bệnh nhân. Ví dụ về các xét\nnghiệm tại chỗ bao gồm:\n• Xét nghiệm đường huyết POCT\n• Xét nghiệm khí máu POCT\n\n• Xét nghiệm thai kỳ\n• Phân tích nước tiểu\n• Xét nghiệm tìm chất ẩn trong phân\n• Xét nghiệm nhiễm trùng nhanh, bao gồm liên cầu khuẩn và COVID\n\nPOCT không bao gồm các xét nghiệm được thực hiện tại hoặc gần bệnh nhân nhưng được xử lý hoặc diễn giải\nở một địa điểm khác.\n\nXét nghiệm kiểm soát chất lượng diễn ra dựa trên hướng dẫn của nhà sản xuất. Các ví dụ về thời điểm diễn ra\nxét nghiệm kiểm soát chất lượng bao gồm:\n• Một lần mỗi ngày\n• Một lần mỗi tuần\n• Giữa các lô bộ xét nghiệm mới\n\nĐánh giá POCT có thể được thực hiện bằng một hoặc nhiều phương pháp sau:\n• Phát triển và giám sát các biện pháp cải thiện chất lượng\n• Phỏng vấn bệnh nhân hoặc tiến hành khảo sát\n• Xem xét kết quả kiểm soát chất lượng và xét nghiệm năng lực\n• Xem xét báo cáo sử dụng.","m":[{"t":"Người chịu trách nhiệm quản lý các dịch vụ phòng xét nghiệm hoặc người được chỉ định sẽ giám sát và quản lý chương trình POCT.","b":[]},{"t":"Nhân viên thực hiện POCT có đủ trình độ và đào tạo cần thiết và có đủ năng lực để thực hiện POCT.","b":[]},{"t":"Chương trình POCT bao gồm một quy trình được xác định để báo cáo kết quả xét nghiệm bất thường, bao gồm báo cáo kết quả quan trọng. (Xem thêm IPSG.02.00, ME 1)","b":[]},{"t":"Chương trình POCT bao gồm các yêu cầu về hiệu suất kiểm soát chất lượng và tài liệu.","b":[]},{"t":"Chương trình POCT được giám sát, đánh giá và đưa vào các hoạt động cải tiến chất lượng.","b":[]}],"sec":"Dịch vụ phòng thí nghiệm"},{"c":"AOP.03.03","ch":"AOP","t":"Kết quả xét nghiệm được báo cáo trong khung thời gian quy định của chính sách bệnh viện.","p":"Báo cáo kết quả kịp thời là rất quan trọng để đánh giá và chẩn đoán bệnh nhân kịp thời.\n\nBệnh viện xác định khung thời gian để báo cáo kết quả xét nghiệm. Kết quả được báo cáo trong khung thời gian dựa\ntrên nhu cầu của bệnh nhân, dịch vụ được cung cấp và nhu cầu của nhân viên lâm sàng. Bao gồm các xét nghiệm\nkhẩn cấp hoặc xét nghiệm theo quy định và nhu cầu xét nghiệm sau giờ làm việc và cuối tuần.\n\nBệnh viện theo dõi xem kết quả có được báo cáo trong khung thời gian hay không. Kết quả từ các xét nghiệm theo\nquy định được đặc biệt chú ý trong quá trình đo lường chất lượng. Nếu kết quả không được báo cáo theo khung\nthời gian của bệnh viện, bệnh viện sẽ xác định các rào cản để đạt được mục tiêu này và thực hiện các hành động\nkhắc phục.\n\nNgoài ra, khi các dịch vụ xét nghiệm được ký hợp đồng với một tổ chức bên ngoài, các báo cáo cũng được thực hiện\nkịp thời, theo quy định của chính sách bệnh viện hoặc hợp đồng.","m":[{"t":"Bệnh viện có chính sách bằng văn bản thiết lập thời gian báo cáo dự kiến cho kết quả xét nghiệm thường quy và xét nghiệm đột xuất.","b":[]},{"t":"Bệnh viện theo dõi xem các xét nghiệm thống kê có được báo cáo trong khung thời gian dự kiến hay không.","b":[]},{"t":"Bệnh viện theo dõi xem kết quả xét nghiệm thường quy có được báo cáo trong khung thời gian dự kiến hay không.","b":[]},{"t":"Khi kết quả xét nghiệm không được báo cáo trong khung thời gian dự kiến, bệnh viện sẽ thực hiện hành động khắc phục.","b":[]}],"sec":"Dịch vụ phòng thí nghiệm"},{"c":"AOP.03.04","ch":"AOP","t":"Tất cả các thiết bị thử nghiệm trong phòng thí nghiệm đều được kiểm tra, bảo trì và hiệu chuẩn thường xuyên, đồng thời lưu giữ hồ sơ phù hợp cho các hoạt động này.","p":"Việc bảo trì và hiệu chuẩn thiết bị phòng thí nghiệm đúng cách là điều cần thiết để đảm bảo độ chính xác của kết quả xét\nnghiệm.\n\nNhân viên phòng thí nghiệm đảm bảo rằng tất cả các thiết bị, bao gồm cả thiết bị y tế được sử dụng để xét nghiệm tại chỗ,\nđều hoạt động bình thường. Phòng thí nghiệm triển khai một chương trình để quản lý thiết bị. Tần suất thử nghiệm, bảo\ntrì và hiệu chuẩn được hoàn thành theo hướng dẫn của nhà sản xuất hoặc thường xuyên hơn dựa trên việc phòng thí\nnghiệm sử dụng thiết bị và lịch sử dịch vụ được ghi chép lại.\n\nChương trình quản lý thiết bị phòng thí nghiệm bao gồm những nội dung sau:\n• Lựa chọn và mua thiết bị phòng thí nghiệm và thiết bị y tế\n• Xác định và kiểm kê thiết bị phòng thí nghiệm và thiết bị y tế\n• Đánh giá việc sử dụng thiết bị phòng thí nghiệm thông qua kiểm tra, thử nghiệm, hiệu chuẩn và bảo trì\n• Theo dõi và hành động theo thông báo nguy cơ, thu hồi, sự cố có thể báo cáo,\nvấn đề và lỗi của thiết bị phòng thí nghiệm\n• Ghi lại chương trình quản lý","m":[{"t":"Phòng thí nghiệm quản lý thiết bị phòng thí nghiệm bằng một quy trình bằng văn bản về cách lựa chọn và mua sắm thiết bị.","b":[]},{"t":"Có một bản kiểm kê tất cả các thiết bị phòng thí nghiệm. (Xem thêm FMS.07.00, ME 2)","b":[]},{"t":"Thiết bị phòng thí nghiệm được kiểm tra và thử nghiệm khi mới và theo hướng dẫn của nhà sản xuất; các cuộc kiểm tra được ghi lại.","b":[]},{"t":"Thiết bị phòng thí nghiệm được hiệu chuẩn và bảo trì theo hướng dẫn của nhà sản xuất và việc hiệu chuẩn và bảo trì được ghi chép lại.","b":[]},{"t":"Bệnh viện giám sát và hành động theo các thông báo nguy hiểm về thiết bị phòng thí nghiệm, thu hồi, sự cố cần báo cáo, vấn đề và lỗi. (Xem thêm FMS.07.01, ME 1)","b":[]}],"sec":"Dịch vụ phòng thí nghiệm"},{"c":"AOP.03.05","ch":"AOP","t":"Thuốc thử và vật tư thiết yếu đều có sẵn và tất cả thuốc thử đều được đánh giá để đảm bảo độ chính xác và độ tin cậy của kết quả.","p":"Thuốc thử là thành phần cần thiết của xét nghiệm trong phòng thí nghiệm, do đó bệnh viện tạo ra chính sách\nđể đảm bảo rằng các thuốc thử thiết yếu có sẵn và đáp ứng mục đích của chúng cho các xét nghiệm trong\nphòng thí nghiệm. Bệnh viện đã xác định các thuốc thử và vật tư cần thiết để cung cấp dịch vụ xét nghiệm\ncho bệnh nhân của mình. Có một quy trình để đặt hàng hoặc đảm bảo các thuốc thử và vật tư thiết yếu.\n\nPhòng xét nghiệm xây dựng và triển khai các hướng dẫn đánh giá định kỳ tất cả các thuốc thử, nhằm đảm bảo độ\nchính xác và độ tin cậy của kết quả xét nghiệm trong phòng xét nghiệm. Hiệu suất và tính đầy đủ của thuốc thử\nđược xác minh trước khi sử dụng. Tất cả các thuốc thử thiết yếu đều được đánh giá theo chỉ thị của nhà sản xuất\nhoặc hướng dẫn đóng gói. Chính sách của bệnh viện yêu cầu phải dán nhãn thuốc thử và dung dịch đầy đủ và\nchính xác.","m":[{"t":"Các thuốc thử và vật tư thiết yếu được xác định và có sẵn, và có một quy trình để giải quyết khi các thuốc thử thiết yếu không có sẵn. (Xem thêm FMS.05.00, ME 2)","b":[]},{"t":"Tất cả các thuốc thử được lưu trữ và phân phối theo hướng dẫn của nhà sản xuất.","b":[]},{"t":"Phòng xét nghiệm thiết lập và tuân thủ chính sách bằng văn bản của bệnh viện để đánh giá tất cả các thuốc thử nhằm đảm bảo độ chính xác và độ tin cậy của kết quả.","b":[]},{"t":"Tất cả các thuốc thử đều trải qua thử nghiệm kiểm soát chất lượng theo yêu cầu của nhà sản xuất.","b":[]},{"t":"Hồ sơ thuốc thử bao gồm các thông tin sau:","b":["Nhận dạng thuốc thử","Ngày nhận hoặc chuẩn bị","Số lô","Ngày hết hạn","Ngày đưa vào sử dụng(See also FMS.05.00, ME 2)"]}],"sec":"Dịch vụ phòng thí nghiệm"},{"c":"AOP.03.06","ch":"AOP","t":"Các thủ tục thu thập, xác định, xử lý, vận chuyển và thải bỏ mẫu vật một cách an toàn được thiết lập và thực hiện.","p":"Cần quản lý mẫu xét nghiệm đúng cách để đảm bảo kết quả xét nghiệm phản ánh chính xác tình trạng bệnh nhân;\nmẫu xét nghiệm phải được dán nhãn đúng cách để mẫu xét nghiệm và kết quả xét nghiệm phù hợp với bệnh nhân.\n\nCác quy trình được thiết lập và triển khai cho các mục đích sau:\n• Đặt hàng xét nghiệm trong phòng xét nghiệm\n• Thu thập và xác định mẫu xét nghiệm\n• Vận chuyển, lưu trữ và bảo quản mẫu xét nghiệm\n• Tiếp nhận, ghi nhật ký và theo dõi mẫu xét nghiệm\n• Xử lý mẫu xét nghiệm\n\nCác quy trình này được áp dụng cho các mẫu xét nghiệm được gửi đến các dịch vụ xét nghiệm theo hợp đồng để xét\nnghiệm.","m":[{"t":"Các thủ tục được thiết lập và triển khai để sắp xếp các xét nghiệm.","b":[]},{"t":"Các thủ tục được thiết lập và triển khai để thu thập và nhận dạng mẫu vật.","b":[]},{"t":"Các thủ tục được thiết lập và triển khai để vận chuyển, lưu trữ và bảo quản mẫu vật.","b":[]},{"t":"Các thủ tục được thiết lập và triển khai để tiếp nhận và theo dõi mẫu vật.","b":[]},{"t":"Các thủ tục được thiết lập và triển khai để xử lý mẫu vật.","b":[]},{"t":"Các thủ tục được tuân theo khi sử dụng các dịch vụ phòng xét nghiệm theo hợp đồng. Đánh giá bệnh nhân (AOP)","b":[]}],"sec":"Dịch vụ phòng thí nghiệm"},{"c":"AOP.03.07","ch":"AOP","t":"Các chuẩn mực và phạm vi đã thiết lập được sử dụng để giải thích và báo cáo kết quả xét nghiệm lâm sàng.","p":"Các chuẩn mực và phạm vi là cần thiết để giải thích kết quả xét nghiệm; các chuẩn mực và phạm vi này được bao\ngồm trong kết quả xét nghiệm để các nhà cung cấp dịch vụ chăm sóc sức khỏe có thể giải thích kết quả xét nghiệm.\n\nPhòng xét nghiệm thiết lập các khoảng tham chiếu hoặc phạm vi \"bình thường\" cho mỗi xét nghiệm được thực\nhiện. Phạm vi được đưa vào hồ sơ y tế, dưới dạng một phần của báo cáo hoặc bằng cách bao gồm danh sách\nhiện tại các giá trị như vậy đã được\nngười đứng đầu phòng xét nghiệm chấp thuận. Phạm vi được cung cấp khi một dịch vụ xét nghiệm theo hợp\nđồng thực hiện xét nghiệm. Phạm vi tham chiếu phù hợp với địa lý và đặc điểm nhân khẩu học của bệnh nhân của\nbệnh viện. Phạm vi tham chiếu được xem xét và cập nhật khi các phương pháp xét nghiệm thay đổi và để phản\nánh bằng chứng khoa học hiện tại.","m":[{"t":"Phòng xét nghiệm thiết lập phạm vi tham chiếu cho mỗi xét nghiệm được thực hiện.","b":[]},{"t":"Phạm vi được đưa vào hồ sơ y tế tại thời điểm kết quả xét nghiệm được báo cáo.","b":[]},{"t":"Phạm vi được cung cấp khi các xét nghiệm được thực hiện bởi các dịch vụ xét nghiệm theo hợp đồng.","b":[]},{"t":"Phạm vi phù hợp với địa lý và đặc điểm nhân khẩu học của bệnh nhân của bệnh viện.","b":[]},{"t":"Phòng xét nghiệm xem xét và cập nhật phạm vi khi cần.","b":[]}],"sec":"Dịch vụ phòng thí nghiệm"},{"c":"AOP.03.08","ch":"AOP","t":"Bệnh viện đã triển khai các quy trình kiểm soát chất lượng và thử nghiệm năng lực dịch vụ xét nghiệm.","p":"Các quy trình kiểm soát chất lượng và thử nghiệm năng lực được thiết kế tốt là điều cần thiết để cung cấp các dịch\nvụ phòng xét nghiệm chính xác.\n\nCác quy trình kiểm soát chất lượng được sử dụng để xác nhận các phương pháp và kết quả thử nghiệm. Kiểm soát\nchất lượng cũng bao gồm giám sát hàng ngày để đảm bảo rằng việc thử nghiệm được hoàn thành theo đúng quy\ntrình. Các hành động khắc phục nhanh chóng được thực hiện khi phát hiện ra các thiếu sót.\n\nPhòng xét nghiệm tham gia vào chương trình thử nghiệm năng lực đã được phê duyệt hoặc đánh giá chất lượng bên\nngoài khi có thể. Thử nghiệm năng lực xác định mức độ kết quả của từng phòng xét nghiệm so sánh với các phòng\nxét nghiệm khác sử dụng cùng phương pháp. Thử nghiệm năng lực có thể xác định các vấn đề về hiệu suất mà các\ncơ chế nội bộ không nhận ra.\n\nCác quy trình kiểm soát chất lượng bao gồm:\n• Xác nhận các phương pháp thử nghiệm được sử dụng để xác định độ chính xác, độ chính xác và phạm vi báo cáo\n• Giám sát kết quả hàng ngày của nhân viên phòng xét nghiệm có trình độ\n• Hành động khắc phục nhanh chóng khi phát hiện ra thiếu sót\n• Ghi lại kết quả và hành động khắc phục\n\nNếu không có chương trình thử nghiệm năng lực đã được phê duyệt hoặc đánh giá chất lượng bên ngoài, phòng xét\nnghiệm sẽ trao đổi mẫu với phòng xét nghiệm ở bệnh viện khác để so sánh với các phòng xét nghiệm khác. Thử\nnghiệm năng lực hoặc phương án thay thế được thực hiện cho tất cả các chương trình xét nghiệm chuyên khoa.\n\nPhòng thí nghiệm lưu giữ hồ sơ về việc tham gia chương trình thử nghiệm năng lực.\n\nĐánh giá bệnh\nnhân (AOP)","m":[{"t":"Bệnh viện thiết lập và triển khai chương trình kiểm soát chất lượng bằng văn bản cho phòng xét nghiệm lâm sàng.","b":[]},{"t":"Chương trình bao gồm việc xác nhận các phương pháp xét nghiệm về độ chính xác, độ đúng và phạm vi báo cáo.","b":[]},{"t":"Chương trình bao gồm việc giám sát hàng ngày và ghi chép kết quả xét nghiệm.","b":[]},{"t":"Chương trình bao gồm việc sửa chữa nhanh chóng và ghi chép các thiếu sót.","b":[]},{"t":"Phòng xét nghiệm tham gia chương trình thử nghiệm năng lực hoặc một giải pháp thay thế cho tất cả các xét nghiệm trong phòng xét nghiệm khi không có đánh giá chất lượng bên ngoài.","b":[]},{"t":"Kết quả thử nghiệm năng lực của phòng xét nghiệm đáp ứng các tiêu chí hiệu suất thỏa đáng theo luật và quy định.","b":[]}],"sec":"Dịch vụ phòng thí nghiệm"}];})(window);
